-- Combined Mason 1000 + Mason 2000 vocabulary seed
-- Generated from data/mason1000-vocabulary.csv and data/mason2000-vocabulary.csv.
-- Deduplication key: lower(trim(word)). One word is stored once.

begin;

create temp table tmp_mason_vocabulary (
  word text not null,
  part_of_speech text,
  chinese_meaning text not null,
  english_definition text,
  example_sentence text,
  synonyms text[],
  antonyms text[],
  memory_hint text,
  difficulty_level int,
  frequency_level int,
  source_book_chapter text
) on commit drop;








-- Update existing rows first, matched only by normalized word.
update public.vocabulary v
set
  part_of_speech = coalesce(nullif(v.part_of_speech, ''), t.part_of_speech),
  chinese_meaning = t.chinese_meaning,
  english_definition = coalesce(t.english_definition, v.english_definition),
  example_sentence = coalesce(t.example_sentence, v.example_sentence),
  synonyms = coalesce(t.synonyms, '{}'::text[]),
  antonyms = coalesce(t.antonyms, '{}'::text[]),
  memory_hint = coalesce(t.memory_hint, v.memory_hint),
  difficulty_level = greatest(coalesce(v.difficulty_level, 1), coalesce(t.difficulty_level, 1)),
  frequency_level = greatest(coalesce(v.frequency_level, 1), coalesce(t.frequency_level, 1)),
  source_book_chapter = t.source_book_chapter
from tmp_mason_vocabulary t
where lower(trim(v.word)) = lower(trim(t.word));

-- Insert only words that are not already present.
select t.word, t.part_of_speech, t.chinese_meaning, t.english_definition, t.example_sentence, coalesce(t.synonyms, '{}'::text[]), coalesce(t.antonyms, '{}'::text[]), t.memory_hint, t.difficulty_level, t.frequency_level, t.source_book_chapter
from tmp_mason_vocabulary t
where not exists (
  select 1 from public.vocabulary v
  where lower(trim(v.word)) = lower(trim(t.word))
);

commit;
