insert into tmp_mason_vocabulary (word, part_of_speech, chinese_meaning, english_definition, example_sentence, synonyms, antonyms, memory_hint, difficulty_level, frequency_level, source_book_chapter) values
  ('abate', 'v.', '減輕、減少', 'make or become less', 'We are waiting for the storm to abate.', array['dwindle', 'ease', 'ebb', 'lessen']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 26'),
  ('abbreviate', 'v.', '縮寫', 'sth shorten (a word, phrase, etc), esp by omitting letters', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 11 / 字根 brev 短 / 提示 abbreviate 縮寫'),
  ('abdicate', 'v.', '正式放棄（權力等）、退（位）、辭（職）', 'resign from or formally renounce the throne', 'The king was forced to abdicate his throne after a popular uprising. 因為一場民眾起義，國王被迫退位。', '{}'::text[], '{}'::text[], 'ab(離開) + dic(命令) + act → 不再命令 → 退位、辭職', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 57'),
  ('aberrant', 'adj.', '偏差的；越軌的；異常的', 'not following the normal or correct way; deviating from the usual or natural type : ATYPICAL, ABNORMAL', 'aberrant behavior 偏差行為、犯罪行為 chromosome aberration syndrome 染色體畸變症候群', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 21'),
  ('abet', 'v.', '教唆、唆使、煽動', 'sb (in sth) help or encourage sb to commit an offence or do sth wrong', 'abet the commission of a crime 教唆犯罪', array['foment', 'instigate', 'provoke']::text[], '{}'::text[], 'bet 賭博 → 教唆賭博', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 24'),
  ('abeyance', 'n.', '暫停、中止', 'be in abeyance; fall/go into abeyance (of a right, rule, problem, etc) be suspended temporarily; not be in force or use for a time', 'The project is currently in abeyance until we receive further instructions from management. 暫時中止', array['doldrums', 'dormancy']::text[], array['continuance', 'continuation']::text[], '音讀: at bay(在海灣) → 暫停', 1, 1, 'Mason 2000 / Mason 2000 PDF page 98 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('abhorrent', 'adj.', '可恨的、討厭的', 'disgusting; hateful', 'That thief did an abhorrent thing to me--he pissed in my bed. 深惡痛絕的事', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 10'),
  ('abject', 'adj.', '可憐的、卑下的', 'wretched; hopeless', 'living in abject poverty', '{}'::text[], '{}'::text[], 'ab(離開) + ject(泡、扔) → 被人拋棄 → 可憐的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 41 / 字根 ject 拋、扔 / 提示 eject 趕出、射出'),
  ('abjure', 'v.', '發誓放棄、棄絕', 'promise or swear to give up (a claim, an opinion, a belief, etc); renounce formally', 'After much reflection, she decided to abjure her former political beliefs and join a different party. 經過深思熟慮，她決定放棄她 以前的政治信仰，加入另一個黨派。', '{}'::text[], '{}'::text[], 'ab(離開) + jur(發誓) + e → 發誓放棄', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 39'),
  ('abnegate', null, '否認、放棄', 'vt. to give up (rights or a claim, for example); renounce.', 'Abnegating this responsibility is going against the will of the people. 否認棄絕這責任是與人民意志相抗', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 17'),
  ('abominate', 'v.', '厭惡、痛恨', 'feel hatred or disgust for (sth/sb); detest; loathe', null, '{}'::text[], '{}'::text[], 'ab(遠離) + omin(=omen凶兆) → 痛恨凶兆，要遠離', 5, 2, 'Mason 2000 / Mason 2000 PDF page 57 / 字根 omin 預兆、不祥 / 提示 ominous 預兆的、不祥的'),
  ('abrasive', null, '有研磨作用的、有磨蝕作用的', null, 'The waves had an abrasive action on the rocks.', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 71 / 字根 rac, rad, ras, raz 刮、擦 / 提示 erase 擦掉、抹去'),
  ('abreast', 'adv.', '並肩地、並排地', 'side by side (with sb/sth) and facing the same way', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 98 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('abridge', 'v.', '縮短、刪節', 'make shorter, esp by using fewer words; condense', 'a 300-page abridged version of the book 這本書的三百頁濃縮版本', array['abbreviate', 'truncate']::text[], '{}'::text[], '橋(bridge)縮短兩地距離', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 9'),
  ('abscond', 'v.', '潛逃、逃亡', 'go away suddenly and secretly, esp in order to avoid arrest', 'He absconded with the company''s confidential documents. 他帶著公司機密文件潛逃了。', '{}'::text[], '{}'::text[], 'abs(離開) + cond(藏)', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 56'),
  ('absolve', 'v.', '赦免、免除（責任、義務等）', 'sb (fml esp law , ) clear sb (of guilt); declare sb free (from blame, a promise, a duty, etc)', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 79 / 字根 solv, solu 溶解、鬆開 / 提示 dissolve 使溶解、使融化'),
  ('absorbing', null, '有趣的、引人入勝的', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 98 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('abstain', 'v.', '禁絕、放棄；(投票)棄權', 'keep oneself from doing or enjoying sth, esp from taking alcoholic drinks; refrain', 'abstain from drinking // Potential employees, even knowing that they could be denied a job for using marijuana, are still using the drug rather than abstaining and becoming eligible for more jobs.', '{}'::text[], '{}'::text[], 'abs(不) + tain(抓住) → 不抓住 → 放棄', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 31'),
  ('abstemious', 'adj.', '有節制的、節儉的', 'not taking much food or drink; not self-indulgent; moderate', 'an abstemious drinker 一個有節制的飲酒者 // Putin publicly presents himself as upright and abstemious. 普丁公眾上顯得正直 且有節制的', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 18'),
  ('abstinent', null, '飲食有度的、有節制的', null, null, '{}'::text[], '{}'::text[], 'abs(不) + tin(抓住) + ent → 不再被抓住 → 節制', 1, 1, 'Mason 2000 / Mason 2000 PDF page 84 / 字根 tain, ten, tin 保持、維持、抓住 / 提示 contain 包含、容納'),
  ('abstruse', 'adj.', '深奧的、難懂的', 'difficult to understand', 'abstruse concepts/ideas/theories', '{}'::text[], '{}'::text[], 'abs(不) + trus(伸) + e → 伸不進去', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 6'),
  ('absurd', 'adj.', '不合理的、荒謬的', 'unreasonable; not sensible', null, '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 49'),
  ('abundant', null, '豐富的、充裕的', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 90 / 字根 und: wave, flow 波浪、流 / 提示 abundant 豐富的、充裕的'),
  ('abuse', 'v.', '濫用、妄用、辱罵', 'make bad or wrong use of', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 90 / 字根 ut, us 用 / 提示 usable 可用的、能用的'),
  ('abysmal', 'adj.', '糟透的、深不可測的', 'extremely bad', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 98 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('accentuate', 'v.', '強調、以重音讀出、加重音符號於', 'make very noticeable or prominent; emphasize', 'accentuate the positive aspects of the course 強調這門課正面的層面', '{}'::text[], '{}'::text[], 'ac(加強) + cent(唱、說)', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 26'),
  ('accolade', 'n.', '推崇、讚揚', 'praise; approval', 'The young athlete received an accolade for breaking the national record. 這位年輕運動員因打破國家紀錄而受到嘉許。', array['citation', 'commendation', 'encomium', 'eulogy', 'salutation', 'tribute']::text[], '{}'::text[], '把獎牌掛在脖子上', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 56'),
  ('accomplice', 'n.', '同謀者、幫兇', 'person who helps another to do sth wicked or illegal', null, '{}'::text[], '{}'::text[], 'ac + com(共同) + plic(重疊) + e → 共同做', 3, 3, 'Mason 2000 / Mason 2000 PDF page 66 / 字根 pli, plic 彎、折、重疊 / 提示 replicate 折疊、複製'),
  ('accretion', 'n.', '增加', 'growth or increase by means of gradual additions', 'he accretion of sediment in the river delta has led to the formation of new land. 河三角洲沈積物的累積導致了新土地的形成。', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 56'),
  ('accrue', 'v.', '（利息）增大、增多', '(from sth) come as a natural increase or advantage, esp financial; accumulate', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 20 / 字根 cre, crue 增加 / 提示 crescendo （音樂）漸強'),
  ('accuse', 'v.', '譴責、指責', 'sb say that sb has done wrong, is guilty (of sth) or has broken the law', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 22 / 字根 cuse 理由 / 提示 excuse 藉口'),
  ('acerbic', 'adj.', '苦澀的、刻薄的', '(adj.) tasting sour; harsh in language or temper', 'He instantly wished he could take back the acerbic comment.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 34'),
  ('acid', null, '酸的', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 3 / 字根 acerb, acid, acri, acu 尖、酸 / 提示 acid 酸'),
  ('acquiesce', 'v.', '勉強同意、默許', '(fml ) accept sth without protest; offer no opposition (to a plan, conclusion, etc)', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 71 / 字根 qui 平靜、安靜 / 提示 tranquil 平靜的、安寧的'),
  ('acquiescence', null, '默認、默許', null, 'I was surprised by his acquiescence to their demands. 我對於他默許他們的要求感到驚訝', array['compliance', 'compliancy', 'deference', 'docility', 'obedience', 'submissiveness']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 30'),
  ('acquisitive', 'adj.', '貪得無厭的；渴望的', 'keen to acquire things, esp material possessions', 'His acquisitive nature led him to accumulate vast amounts of wealth 他的貪得無厭讓他積累了巨額財富', array['avaricious', 'avid', 'coveting', 'covetous', 'grabby', 'grasping', 'greedy', 'mercenary', 'rapacious']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 49'),
  ('acrid', 'adj.', '辛辣的、刻薄的', 'having a strongly bitter smell or taste', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 3 / 字根 acerb, acid, acri, acu 尖、酸 / 提示 acid 酸'),
  ('acrimonious', 'adj.', '尖刻的、嚴厲的', 'bitter', 'You are liable to face acrimonious reprisals from your enemy once you stepped down from your office. 你下臺之後，很可能面 臨對手刻毒的反擊', array['bitter', 'rancorous', 'resentful']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 15'),
  ('acrimony', 'n.', '尖刻、刻薄', 'bitterness of manner or words', 'Their relationship was filled with acrimony and bitterness.', '{}'::text[], array['civility', 'comity']::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 15'),
  ('acronym', 'n.', '首字母縮略字', 'word formed from the initial letters of a group of words', null, '{}'::text[], '{}'::text[], 'acro(高) + onym(名稱)', 5, 2, 'Mason 2000 / Mason 2000 PDF page 57 / 字根 onym 名字 / 提示 anonymity 匿名、作者不詳'),
  ('acuity', 'n.', '敏銳', '(esp of thought or the senses) sharpness; acuteness', 'The doctor''s acuity allowed him to make an accurate diagnosis.', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 3 / 字根 acerb, acid, acri, acu 尖、酸 / 提示 acid 酸'),
  ('acumen', 'n.', '精明', 'ability to understand and judge things quickly and clearly; shrewdness', 'business acumen 商業上的精明、商業頭腦', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 34'),
  ('acute', 'adj.', '靈敏的；劇烈的', 'very great; severe', 'The patient was suffering from acute pain in his chest.', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 3 / 字根 acerb, acid, acri, acu 尖、酸 / 提示 acid 酸'),
  ('ad hoc', null, '臨時的、特別安排的', null, 'an ad hoc investigating committee', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 98 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('adamant', 'adj.', '堅決的、固執的', 'firmly or stubbornly determined; unwilling to be persuaded', 'He is very adamant about signing the peace treaty. Your opposing opinions will only prove inconsequential. 他很堅決地要簽署和平 協議。你的反對意見將證明為微不足道的', array['unyielding', 'immovable', 'implacable']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 50'),
  ('adaptive', null, '適應的', null, 'Webbed feet is an adaptive trait in aquatic animals. 適應性的特徵', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 26'),
  ('adduce', 'v.', '引用、舉例', 'put (sth) forward as an example or as proof', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 26 / 字根 duct, duc 引導 / 提示 conduct 品德、行為'),
  ('adept', 'adj.', '熟練的、內行的', 'thoroughly proficient : EXPERT', 'Pyongyang has grown adept over the years at evading sanctions 規避制裁 imposed by the U.S. and the United Nations, using an array of tactics to gain revenue. — Samuel Rubenfeld, WSJ', array['proficient', 'versed', 'veteran', 'virtuoso']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 34'),
  ('adequate', 'adj.', '足夠的；適當的', 'satisfactory in quantity or quality; sufficient', 'this office is perfectly adequate for my needs 足夠的 // the law is adequate to deal with the problem 適當的', '{}'::text[], array['inadequate']::text[], 'ad(使) + equ(平等) + ate', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 16'),
  ('adhere', 'v.', '黏著；堅持', '(to sth) remain attached (to sth); stick (as if) by means of glue or suction', 'It is more harmful to compromise one''s own beliefs than to adhere to them. - GRE Issue題', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 39 / 字根 here: stick to 粘黏 / 提示 adhere 黏著、堅持'),
  ('adherent', 'n.', '擁護者、信徒', 'supporter of a party or doctrine', null, '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 58'),
  ('adhesive', null, '黏的、黏著的、有黏性的', null, null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 39 / 字根 here: stick to 粘黏 / 提示 adhere 黏著、堅持'),
  ('adjourn', 'v.', '使延期、推遲、休會', 'stop (a meeting, etc) for a time; postpone', null, '{}'::text[], '{}'::text[], 'ad(=to) + journ(天) → 推到另一天 → 延期', 5, 2, 'Mason 2000 / Mason 2000 PDF page 41 / 字根 journ 天 / 提示 journal 日記、日報'),
  ('adjunct', 'n.', '附加物、附件、助手', 'thing that is added or attached to sth else but is less important and not essential', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 42 / 字根 junct 結合、連接 / 提示 conjunction 連接詞、聯合'),
  ('admonish', null, '告誡、警告', 'to express warning or disapproval to especially in a gentle, earnest, or solicitous manner', 'The teacher had to admonish the students for talking during the exam. 老師不得不警告學生在考試期間交頭接耳。', array['reprove']::text[], '{}'::text[], 'ad: at; mon: moon 指月亮', 1, 1, 'Mason 2000 / Mason 2000 PDF page 52 / 字根 mon 警告 / 提示 admonish 告誡、警告'),
  ('adolescent', 'adj.', '青少年、青春期的', 'of or typical of adolescence', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 98 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('adore', 'v.', '崇拜、敬愛、傾慕', 'love deeply and respect (sb) highly', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 58 / 字根 or, ora 口、說 / 提示 adore 敬愛、傾慕'),
  ('adroit', 'adj.', '靈巧的、熟練的', 'skilful; clever', 'He was adroit at tax avoidance. 他很善於避稅', array['dexterous', 'nimble (敏捷的)', 'artful', 'deft', 'masterful', 'virtuoso']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 21'),
  ('adulation', null, '諂媚、奉承', null, 'The rugby player enjoyed the adulation of his fans. 橄欖球員享受粉絲的諂媚奉承', array['flattery v. adulate']::text[], array['opprobrium 譴責', '咒罵']::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 7'),
  ('adumbrate', 'v.', '預示、遮蔽', 'indicate (sth) faintly or in outline', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 90 / 字根 umbr 影子 / 提示 umbrella 雨傘'),
  ('adventurous', 'adj.', '愛冒險的、大膽的', 'eager for or fond of adventure', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 92 / 字根 ven, vent 到來 / 提示 revenue 總收入、國家稅收收入'),
  ('adversary', 'n.', '敵手、對手', 'opponent in a contest; enemy', 'His political adversaries tried to prevent him from winning the nomination. 他政治上的對手嘗試防止他獲得提名', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 31'),
  ('adverse', 'adj.', '不利的、相反的', 'not favourable; contrary', null, '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 2000 / Mason 2000 PDF page 93 / 字根 vert, vers 轉 / 提示 reverse 倒車、反轉'),
  ('adversity', 'n.', '逆境、不幸', 'unfavourable conditions; trouble', 'adverse weather We had to learn to deal with adversity. 對抗逆境', '{}'::text[], '{}'::text[], 'adverse 不利的、逆境的', 5, 5, 'Mason 2000 / Mason 2000 PDF page 93 / 字根 vert, vers 轉 / 提示 reverse 倒車、反轉'),
  ('advocate', 'v.', '擁護、支持、鼓吹', 'speak publicly in favour of (sth); recommend; support', 'They advocated a return to traditional teaching methods. 他們支持回歸傳統式的教學法', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 24'),
  ('aerate', 'v.', '充氣、使空氣進入', 'add carbon dioxide to under pressure', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 3 / 字根 aer 空氣 / 提示 air 空氣'),
  ('aerial', 'n.', '空中的、空氣中的', 'one or more wires or rods for sending or receiving radio waves .', 'The drone captured stunning aerial footage of the city skyline.', '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 3 / 字根 aer 空氣 / 提示 air 空氣'),
  ('aeronautics', 'n.', '航空學', 'scientific study or practice of flying and navigating aircraft', null, '{}'::text[], '{}'::text[], 'aero(空氣) + nau(船) + tics', 5, 2, 'Mason 2000 / Mason 2000 PDF page 4 / 字根 aer 空氣 / 提示 air 空氣'),
  ('aesthetic', null, '美學的、有審美感的', null, 'Philistine (庸俗的人) hide no secret his disdain (鄙視、厭惡) of aesthetic endeavor (努力、付出).', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 6'),
  ('affable', 'adj.', '和藹可親的、容易親近的', 'polite and friendly', 'an affable host 和藹可親的東道主', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 27'),
  ('affected', 'adj.', '不自然的、假裝的', 'not natural or genuine; pretended; artificial', 'spoke in an affected manner', '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 29 / 字根 fect 做 / 提示 affect 影響'),
