  ('cagey', 'adj.', '謹慎的；機敏的', '(about sth) (infml ) cautious about giving information; wary; secretive', 'give a cagey response', '{}'::text[], '{}'::text[], '尼可拉斯·凱吉(Nicolas Cage)很謹慎的', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 51'),
  ('cajole', 'v.', '勾引、誘騙', 'sb(into/out of sth); sb (into/out of doing sth) persuade sb (to do sth) by flattery or deceit; coax sb', 'She tried to cajole him into coming to the party. 她試圖誘哄他來參加派對。', array['coax', 'wheedle']::text[], '{}'::text[], 'catch', 1, 1, 'Mason 2000 / Mason 2000 PDF page 102 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('calamity', 'n.', '災難、禍患', 'serious misfortune or disaster', 'an economic calamity', array['disaster', 'cataclysm']::text[], '{}'::text[], '災難來了一定要calm才活得下去', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 19'),
  ('calculate', 'v.', '計算', 'work out by using numbers or one''s judgement; estimate', null, '{}'::text[], '{}'::text[], '以石頭算數', 1, 1, 'Mason 2000 / Mason 2000 PDF page 12 / 字根 calc 石灰、石頭 / 提示 calcium 鈣'),
  ('callous', 'adj.', '無情的、硬結的', 'cruelly insensitive or unsympathetic', 'His callous comments about the murder made me shiver. 他對謀殺的冷漠無情的評論使得我打顫', array['cold-blooded', 'inhumane', 'merciless', 'ruthless', 'unsympathetic']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 20'),
