  ('cantankerous', 'adj.', '愛唱反調的、脾氣壞的', 'bad-tempered; quarrelsome', 'a cantankerous old man(壞脾氣的老人)', array['contentious', 'malicious', 'irascible']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 13 / 字根 cant, cent, chant 唱、歌唱 / 提示 chant 歌唱、背誦'),
  ('capacious', 'adj.', '容量大的、寬敞的', 'that can hold much; roomy', null, '{}'::text[], '{}'::text[], '能抓住東西的 → 容量大的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 13 / 字根 cap 拿、抓住 / 提示 capture 捕獲、俘虜'),
  ('capitulate', 'v.', '（有條件）投降', 'surrender (to sb), esp on agreed conditions', 'In total, Trump has threatened tariffs on up to $450 billion of Chinese products if Beijing refuses to capitulate. — New York Times', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 55'),
  ('capricious', 'adj.', '變化無常的、任性的', 'characterized by sudden changes in attitude or behaviour; unpredictable; impulsive', 'Given the historically volatile nature (易變的特性) of operations and dealing in China and the particularly capricious relationship with authorities (官方、當局、主管機關) , coupled with the stagnating (停滯的) share movement, the company’s future in the region becomes more precarious (危險的).', array['erratic']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
