  ('categorical', 'adj.', '絕對的、至上的', 'unconditional; absolute; explicit', 'a categorical denial 嚴正否認 // Apple and Amazon, for their part, responded with unusually specific and categorical denials.', '{}'::text[], '{}'::text[], '分類是種絕對的權力', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 51'),
  ('caterwaul', 'v.', '嚎叫、尖叫；大聲抗議；大聲嚷嚷；貓叫春', 'to make a harsh cry; to protest or complain noisily', 'This guy starts caterwauling about his 1st Amendment rights.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 32'),
  ('caustic', 'adj.', '腐蝕性的；刻薄的', 'marked by incisive (尖銳的；鋒利的) sarcasm; that can burn or destroy things by chemical action', 'a caustic cousin 講話刻薄的', array['acerbic']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 55'),
  ('cavalier', 'adj.', '騎士、武士；滿不在乎的；目空一切的', 'marked by or given to offhand and often disdainful dismissal of important matters // n. a gentleman trained in arms and horsemanship', 'a cavalier reply 漫不經心的回答 // his cavalier attitude他目空一切的態度', '{}'::text[], '{}'::text[], 'cavalry 騎兵部隊', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 27'),
  ('cavalry', 'n.', '騎兵隊伍、裝甲部隊', 'soldiers fighting on horseback or in armoured vehicles', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 14 / 字根 caval 騎馬 / 提示 cavalry 騎兵隊伍、裝甲部隊'),
  ('cavity', 'n.', '洞、腔', 'empty space within sth solid, eg a hole in a tooth ,', 'cavities in teeth 牙齒內的蛀洞', '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 14 / 字根 cav 洞 / 提示 cave 洞'),
  ('celerity', 'n.', '迅速、快速', 'quickness', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 15 / 字根 celer 速度 / 提示 accelerate 加速、促進'),
  ('censor', 'n.', '審查、檢查', 'person authorized toexamine books, films, plays, letters, etc and remove partswhich are considered indecent, offensive, politically unacceptable or a threat to security', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 15 / 字根 cens 評估 / 提示 censor 審查、檢查'),
  ('censorious', 'adj.', '好批評的、好吹毛求疵的', 'tending to find faults in people or things; severely critical', 'I was surprised by the censorious tone of the book review. 我對本書的好批評語調感到驚訝', array['captious']::text[], '{}'::text[], 'censure 責備、譴責之形容詞', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 16'),
  ('censure', 'v.', '責備、譴責', 'sb criticize sb severely; rebuke sb formally', 'The judge censured the driver but didn''t fine him. 法官責難了駕駛但沒罰他錢', array['condemn', 'denounce', 'objurgate', 'rebuke', 'reprimand', 'reproach', 'reprove']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 10'),
