  ('concord', 'n.', '一致、協調、（國際的）和睦', 'harmony between people; lack of quarrelling and unfriendliness', 'These neighboring states had lived in concord for centuries.', array['chime', 'comity', 'compatibility', 'harmony', 'peace']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 56'),
