  ('confine', 'v.', '限制、使局限', 'sb/sth keep (a person or an animal) in a restricted space', 'Please confine your use of the phone to business calls. 限縮電話使用於公務用途', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 38'),
