  ('contagious', 'adj.', '傳染的、有感染力的', '(of a disease) spreading by contact', 'her enthusiasm is contagious', '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 84 / 字根 tach, tact, tag, tig, ting, tamin, tang 接觸 / 提示 contact 接觸、聯絡'),
  ('contemplate', 'v.', '沉思、凝視', 'look at or consider (sth) thoughtfully', 'The consequences of the disaster were too dreadful to contemplate. 災難的後果讓人無法設想。', array['entertain', 'meditate', 'ponder']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 47'),
