  ('convection', null, '傳遞、傳送、熱對流', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 92 / 字根 ven, vent 到來 / 提示 revenue 總收入、國家稅收收入'),
  ('conventional', 'adj.', '慣例的、習俗的、常規的、傳統的', 'based on convention (usage or custom especially in social matters); lacking originality or individuality; commonplace', 'reduce conventional forces 減少傳統武器 (非核武器)', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 2'),
  ('convergent', null, '匯聚的', 'tending to move toward one point or to approach each other:CONVERGING', 'The convergent lines in the distance seem to meet at a point. 遠處的匯聚線似乎會在一點相會。', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 48'),
  ('conversant', 'adj.', '熟悉的、精通的', 'with sth having knowledge of sth; familiar with sth', 'She is conversant in several languages. 她能說數種語言。', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 48'),
  ('convert', 'v.', '轉變、使改變信仰', 'to bring over from one belief, view, or party to another; to change from one form or function to another', 'After years of searching, she chose to convert to Buddhism. 經過多年的探索，她決定皈依佛教', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 93 / 字根 vert, vers 轉 / 提示 reverse 倒車、反轉'),
  ('conviction', 'n.', '判罪；堅信', 'the act or process of finding a person guilty of a crime especially in a court of law', 'He spoke with conviction, and everyone in the room believed him. 他說話伴隨著堅信，房間裡的每個人都相信他。', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 49'),
  ('convoluted', 'adj.', '費解的、旋繞的', 'coiled; twisted; INVOLVED, INTRICATE', 'plans too convoluted to materialize 太複雜以至於無法實現的計畫 // a convoluted explanation 錯綜複雜的解釋', array['coiled', 'spiraled(費解的)', 'intricate(錯綜複雜的)']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 31'),
  ('convulsion', 'n.', '抽搐、驚厥', 'sudden violent uncontrollable body movement, caused by contraction of muscles', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 71 / 字根 puls, vuls 推、衝 / 提示 impulse 衝動、刺激'),
  ('copious', 'adj.', '豐富的、多產的', 'plentiful; abundant', 'I have prepared a copious amount of notes to study for the exam. 為了準備考試，我準備了大量的筆記', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 56'),
