  ('dejected', 'adj.', '沮喪的、失望的', 'depressed; sad', 'The team was dejected after the loss.', array['depressed', 'despondent', 'doleful', 'forlorn', 'gloomy', 'melancholy']::text[], '{}'::text[], '被人拋棄 → 沮喪', 1, 1, 'Mason 2000 / Mason 2000 PDF page 41 / 字根 ject 拋、扔 / 提示 eject 趕出、射出'),
