  ('delimit', 'v.', '確定…界線、界定、限定', 'fix the limits or boundaries of', 'We need to delimit the scope and objectives 我們需要界定專案範圍和目標。', array['circumscribe', 'demarcate', 'demark', 'mark (off)']::text[], '{}'::text[], 'de(向下) + limit(界線) → 劃下界線 → 確定界線', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 67'),
  ('delineate', 'v.', '描繪、描寫', 'show (sth) by drawing or describing; portray', 'The resulting Transcontinental Treaty of 1819 ceded 割讓；放棄 Florida to the United States and delineated the boundary between American and Spanish territory all the way to the Pacific Ocean … 描繪兩國邊界', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 59'),
