  ('demean', 'v.', '貶低﹐貶損', 'oneself lower oneself in dignity; deprive oneself of others'' respect', 'Politicians'' tendency to tout their own virtues by demeaning their opponents is injudicious: what if voters forget the name of the candidate and remember only that of his adversary?', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 2000 / Mason 2000 PDF page 49 / 字根 men: threat 威脅 / 提示 menace 威脅、恐嚇'),
  ('demeanor', null, '舉動、行為、風度', 'behavior; bearing ; behavioral attributes', 'a haughty demeanor 高傲的舉止 // a shy demeanor', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 34'),
  ('demented', 'adj.', '精神錯亂狀態的、瘋狂的', 'mad', null, '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 2000 / Mason 2000 PDF page 50 / 字根 ment 思考、心智 / 提示 mental 心智的'),
  ('demise', 'n.', '死亡；財產轉讓', 'death', 'The demise of the company was caused by mismanagement and a failure to adapt to changing market conditions. 公司的倒閉是由 於管理不善和未能適應市場變化所致。', array['curtains', 'death', 'decease', 'doom', 'passing']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 60'),
  ('demography', 'n.', '人口統計、人口學', 'study of statistics of births, deaths, diseases, etc in order to show the state of a community', null, '{}'::text[], '{}'::text[], 'demo(人民) + graphy(寫) → 寫出人口數量 → 人口統計', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 58'),
  ('demonstrable', 'adj.', '可證明的、顯而易見的', 'that can be shown or proved', 'As a scientist, she is only interested in demonstrable phenomena. 作為一個科學家，他只對可證成的現象感興趣', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 22'),
  ('demonstrative', 'adj.', '證明性的、喜怒形於色的', '(of people) showing the feelings readily', null, '{}'::text[], array['a. undemonstrative 不露感情的']::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 52 / 字根 monstr 表示 / 提示 demonstrate 證明、展示'),
  ('demoralize', null, '使士氣低落', 'a:to weaken the morale of:DISCOURAGE, DISPIRIT b:to upset or destroy the normal functioning of c:to throw into disorder', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 53 / 字根 mor 習俗、民心 / 提示 moral 道德的'),
  ('demote', 'v.', '降級、降職', 'sb (to sth) reduce sb to a lower rank or grade', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 53 / 字根 mot 動 / 提示 motivate 給…動機、刺激'),
  ('demotic', 'adj.', '大眾的、通俗的', 'of or used by ordinary people', 'a demotic idiom', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 23 / 字根 dem 人民 / 提示 democracy 民主'),
  ('demur', 'v.', '表示異議、反對', '(at sth) (fml ) express a doubt (about sth) or an objection (to sth)', 'They demurred at the proposal. 他們反對那項建議', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 22'),
  ('demystify', 'v.', '弄清楚', 'make (sth) less mysterious; make clear', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 54 / 字根 myst / 提示 mystery 神秘的'),
  ('denigrate', 'v.', '污衊、誹謗', 'claim that (sb/sth) is inferior, worthless, etc; belittle', 'denigrate their opposition', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 41'),
  ('denounce', 'v.', '指責、譴責', 'sb (to sb) (as sth) give information (to the authorities) against sb', null, '{}'::text[], '{}'::text[], 'de(向下) + nounce(宣布) → 譴責', 1, 1, 'Mason 2000 / Mason 2000 PDF page 56 / 字根 nounc, nunc 說出、報告 / 提示 announce 宣布、發布'),
  ('dense', null, '稠密的；愚蠢的；難懂的', null, 'In the movie, he plays his friendly but somewhat dense uncle.', array['witless']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 105 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('depict', 'v.', '描繪、描畫', 'show (sb/sth) as a picture; portray', 'The painting, Gleaners 拾穗者, depicts three peasant women gleaning a field of stray stalks of wheat after the harvest.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 29'),
  ('deplete', 'v.', '用盡、使減少', 'reduce greatly the quantity, size, power or value of', 'Activities such as logging and mining deplete our natural resources. 耗盡我們的自然資源 // We completely depleted our life savings when we bought our new house. 耗盡我們一生的存款', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 66 / 字根 plet: fill, full 滿、注入 / 提示 complete 完全的、完成'),
  ('deplorable', 'adj.', '悲慘的、應受譴責的', 'deserving censure or contempt; LAMENTABLE', 'The real-world history of how America treated its African-American soldiers in World War II is deplorable, but Overlord never mentions race. — Bryan Bishop, The Verge', array['v. deplore 對…感到遺憾', '譴責', '悲痛']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 67 / 字根 plore 喊 / 提示 explore 探究、考察'),
  ('deprave', null, '使墮落、使惡化', null, null, '{}'::text[], '{}'::text[], 'de(向下) + prave(音讀play) → 整天在下面玩 → 墮落', 1, 1, 'Mason 2000 / Mason 2000 PDF page 68 / 字根 prav 壞 / 提示 deprave 使墮落、使惡化'),
  ('deprecate', 'v.', '不贊同、反對；輕視', 'feel and express disapproval of (sth)', 'The school deprecates this behavior. 譴責這行為', array['譴責: deplore', 'abhor', 'disapprove of', 'frown on', 'detest', 'despise']::text[], '{}'::text[], '(1) 不再祈禱 - 譴責神祇 (2) depreciate 貶值要譴責', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 23'),
  ('deprive', 'v.', '剝奪、使喪失', 'sb/sth of sth take sth away from sb/sth; prevent sb/sth from enjoying or using sth', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 69 / 字根 priv 剝奪、私人的 / 提示 deprive 剝奪、使喪失'),
  ('derelict', 'adj.', '拋棄的、破舊的、棄置的', 'deserted and allowed to fall into ruins; dilapidated', null, array['abandoned']::text[], '{}'::text[], 'de(向下) + relic(遺跡) → 被棄置的、被拋棄的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 105 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('deride', 'v.', '嘲笑、嘲弄', 'sb/sth treat sb/sth as funny and not worthy of serious attention; mock sb/sth', 'Democrats deride Georgia voting law in secretary of state debate.', array['jeer', 'laugh (at)', 'mock', 'ridicule', 'scout']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 63'),
  ('derivative', 'adj.', '非原創的、衍生的 v. derive', 'derived from sth else; not original', 'The word "childish" is a derivative 衍生物 of "child."', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 14'),
  ('derogate', 'v.', '貶低、誹謗', 'from sth cause sth to seem inferior; detract from sth', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 73 / 字根 rog 要求、詢問 / 提示 arrogant 傲慢的、自大的'),
  ('derogatory', 'adj.', '不敬的、貶損的', 'showing a hostile or critical attitude (to sb''s reputation, etc); insulting', '"Japs" is a derogatory terms. You should never use that term to address Japanese.', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 63'),
  ('descry', 'v.', '看出；辨認出', '(fml ) see (sth) esp a long way away; catch sight of', 'We descried the little boat two miles away. 我們望見兩英里外的小船。', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 105 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('desolate', 'adj.', '荒蕪的、無人煙的', 'deserted and miserable', 'a desolate abandoned town 杳無人煙', '{}'::text[], '{}'::text[], 'The Hobbit: The Desolation of Smaug 哈比人：荒谷惡龍', 1, 1, 'Mason 2000 / Mason 2000 PDF page 79 / 字根 sol 孤單、安慰 / 提示 isolate 孤立、隔離'),
  ('desperate', 'adj.', '絕望的；不顧一切的；情急拼命的、鋌而走險的', 'feeling or showing great despair and ready to do anything regardless of danger', 'Jim Abed was in desperate need of a new kidney. — Madeline Farber, Fox News', array['despairing', 'despondent', 'forlorn', 'hopeless']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 46'),
  ('despicable', 'adj.', '可鄙的、卑劣的', '(to do sth) deserving to be despised; contemptible', 'a despicable act 卑鄙的行為', '{}'::text[], '{}'::text[], 'de(不) + spic(看) + able → 不值得看的 → 卑劣的', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 63'),
  ('despotic', null, '暴君的、暴虐的、專橫的', 'characteristic of an absolute ruler or absolute rule; having absolute sovereignty', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 68 / 字根 pot 力量 / 提示 potential 潛在的、有可能性的'),
  ('desultory', 'adj.', '無計畫的、無目的的、不連貫的、散漫的', 'going from one thing to another, without a definite plan or purpose; unmethodical', 'We never really played together, or had any more than desultory conversations.', array['digressive', 'excursive', 'meandering', 'rambling', 'wandering(無目的的)']::text[], array['assiduous(勤奮的)']::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 74 / 字根 sal, sult 跳 / 提示 assault 突然襲擊、猛襲'),
  ('detached', 'adj.', '分開的、超然的、不受影響的', 'exhibiting an aloof objectivity usually free from prejudice or self-interest', 'a detached observer 一個疏離超然的旁觀者', array['aloof', 'distant (v) detach 分開', '拆卸']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 18'),
  ('detect', null, '洞察、查明', null, null, '{}'::text[], '{}'::text[], 'de(除去) + tect(遮蓋)', 1, 1, 'Mason 2000 / Mason 2000 PDF page 85 / 字根 tect 遮蓋 / 提示 protect 保護'),
  ('detection', 'n.', '查出、探獲', 'detecting; discovering', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 85 / 字根 tect 遮蓋 / 提示 protect 保護'),
  ('deterioration', null, '惡化、變壞', null, 'deterioration in United States-Russian relations', array['decay', 'decaying', 'declension', 'decline', 'degeneration', 'descent', 'ebbing', 'enfeeblement', 'weakening']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 51'),
  ('deterrent', null, '威懾的、遏制的', 'adj serving to discourage, prevent, or inhibit : serving to deter', 'If the United States does not take punitive (懲罰的) or deterrent (嚇阻的) action against Russia, its malicious (惡意的) activity will continue. — Washington Post', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 47');
insert into tmp_mason_vocabulary (word, part_of_speech, chinese_meaning, english_definition, example_sentence, synonyms, antonyms, memory_hint, difficulty_level, frequency_level, source_book_chapter) values
  ('detest', 'v.', '厭惡、痛恨', 'dislike very much; hate', 'John detested the abuse of power.', array['abhor', 'abominate', 'despise', 'execrate', 'hate', 'loathe']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 51'),
  ('detonate', 'v.', '使爆炸、引爆', 'explode; (be) set off', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 87 / 字根 ton, tun 聲音 / 提示 tone 語氣、腔調'),
  ('detour', 'n.', '繞道、繞行的路', 'route that avoids a blocked road, etc; deviation', 'You''d be wise to make a detour to avoid the roadworks.', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 64'),
  ('detract', 'v.', '貶低；詆毀；誹謗', 'to diminish the importance, value, or effectiveness of something —often used with from', 'Don''t let one small mistake detract from all the progress you''ve made. 不要讓一個小錯誤影響你所取得的所有進步。', '{}'::text[], '{}'::text[], 'de(向下) + tract(拉) → 政治把別人民調向下拉 → 寄黑函誹謗、詆毀', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 47'),
  ('detrimental', 'adj.', '有害的；不利的', 'harmful', 'Releasing the documents would be detrimental to national security 對國安有害', array['harmful', 'hurtful', 'baneful', 'pernicious', 'noisome', 'deleterious', 'damaging', 'adverse', 'inimical', 'bad']::text[], '{}'::text[], null, 4, 4, 'Mason 2000 / Mason 2000 PDF page 105 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('deviant', null, '越軌的、超出常規的', 'n, adj straying or deviating especially from an accepted norm', 'deviant behavior 越軌的行為', '{}'::text[], '{}'::text[], 'de(離開) + vi(道路) + and → 離開道路', 1, 1, 'Mason 2000 / Mason 2000 PDF page 94 / 字根 vi, vey, voy 道路 / 提示 convey 運載、運送、表達；bon voyage 一路順風'),
  ('deviate', 'v.', '越軌、脫離', 'to stray especially from a standard, principle, or topic', 'You must not deviate (偏離) from the agreed route (路徑).', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 65'),
  ('devious', 'adj.', '狡猾的、不正直的、彎曲的', 'cunning; dishonest', 'He got rich by devious means. 他靠不正當手段發了財', '{}'::text[], '{}'::text[], 'de(離開) + vi(道路) + ous', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 48'),
  ('devoid', 'adj.', '缺乏的、沒有的', 'of sth without sth; completely lacking in sth', 'The moon is a dry and barren place, utterly (完全地) devoid of life. — Avery Thompson', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 49'),
  ('devolve', 'v.', '被轉移、被移交；惡化', 'on/upon sb (of work, duties) be transferred or passed to sb', 'devolving to western Europe full responsibility for its own defense 將全部自衛責任移交給西歐; The scene devolved into chaos. 轉變為混亂', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 97 / 字根 volu, volv, volt 轉 / 提示 evolution 演化'),
  ('devour', 'v.', '狼吞虎嚥地吃、吃光', 'eat (sth) hungrily or greedily', 'The lions devour their prey with great ferocity. 獅子以極大的兇猛吞噬它們的獵物。', array['consume', 'eat (up)']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 65'),
  ('dexterous', 'adj.', '靈巧的、熟練的', 'skilful with one''s hands', 'She was so dexterous with her fingers that she could type on the keyboard without even looking at it. 她的手指非常靈巧，以至於 她甚至可以不看鍵盤就打字。', array['clever', 'cunning', 'deft', 'handy']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 57'),
  ('diameter', 'n.', '直徑', 'straight line connecting the centre of a circle or sphere, or of the base of a cylinder, to two points on its sides', null, '{}'::text[], '{}'::text[], 'dia(穿過) + meter(測量)', 2, 1, 'Mason 2000 / Mason 2000 PDF page 50 / 字根 meter, metr 儀表、測量 / 提示 centimeter 公分'),
  ('diatribe', 'n.', '抨擊', 'lengthy and bitter attack in words', 'He launched into a long diatribe against the lack of action in Congress. 他開始長篇大論地抨擊參議院行動不力', array['harangue', 'jeremiad', 'philippic', 'rant', 'tirade']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 64'),
  ('dichotomy', 'n.', '分裂；二分法；對立', 'a division into two especially mutually exclusive or contradictory groups or entities', 'the dichotomy between theory and practice 理論與實務上的對立 // The amusing spectacle of the recent presidential vote in Florida should remind us of the persistence of the federal-state dichotomy. 在佛羅里達的近期總統選戰的有趣場面應提醒我們聯邦與州 間的對立的持續至今', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 47'),
  ('dictate', 'v.', '口述；命令；決定', 'to speak or act domineeringly : PRESCRIBE; to issue as an order; to impose, pronounce, or specify authoritatively', 'The CEO dictated a new policy that all employees must work overtime without extra pay. CEO 下令所有員工必須加班並且不會 得到額外的薪資。', array['call', 'command', 'decree', 'direct', 'mandate', 'ordain', 'order']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 57'),
  ('didactic', 'adj.', '說教的、教導的', 'intended to teach', 'a didactic approach to teaching 說教式的教學方法', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 10'),
  ('diffident', 'adj.', '缺乏自信的、懦怯的、羞怯的', 'not having or showing much belief in one''s own abilities; lacking self-confidence', 'He was diffident about speaking in front of a large crowd.', array['bashful', 'demure', 'introverted', 'modest', 'recessive', 'self-effacing']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 38'),
  ('diffuse', 'v.', 'v. 四散、擴散 a. 雜亂的', 'spread all around; send out in all directions; a. being at once verbose and ill-organized', 'a drop of blue dye diffused in a glass of water 一滴藍色染劑在一杯水中四散 // a diffuse report from the scene of the earthquake 一個來自地震現場的雜亂無章報導', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 13'),
  ('digressive', null, '離題的、枝節的', 'wandering away from the subject', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 38 / 字根 gress 走 / 提示 aggression 侵略'),
  ('dilatory', 'adj.', '慢吞吞的、磨蹭的', '(in doing sth) slow in acting', 'dilatory progress', array['tardy']::text[], '{}'::text[], '源於 delay', 2, 2, 'Mason 2000 / Mason 2000 PDF page 24 / 字根 di, du 雙 / 提示 dilemma 兩難、困境'),
  ('dilemma', 'n.', '兩難、困境', 'situation in which one has to choose between two undesirable things or courses of action', null, '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 57'),
  ('dilute', 'v.', '弄稀、弄淡', 'sth make (a liquid or colour) thinner or weaker (by adding water or another liquid)', null, '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 59'),
  ('diminish', 'v.', '使減少、縮小', 'become smaller or less; decrease', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 51 / 字根 mini 小 / 提示 miniature 縮圖、小型物'),
  ('diminutive', 'adj.', '非常小的、極小的', 'unusually or remarkably small', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 51 / 字根 minu 變小、減少 / 提示 minutes 會議記錄'),
  ('dire', 'adj.', '非常可怕的、極其嚴重的、悲慘的', 'dreadful; terrible', 'The situation was dire, and they had to act fast to avoid catastrophe. 形勢危急，他們必須迅速採取行動，以避免災難。', array['calamitous', 'dreadful', 'miserable']::text[], '{}'::text[], '音讀「戴爾」 → 面臨蘋果電腦和華碩電腦的夾擊，戴爾處境悲慘 → 悲慘的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 105 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('disabuse', 'v.', '使省悟、糾正', 'sb of sth free sb of (false ideas)', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 90 / 字根 ut, us 用 / 提示 usable 可用的、能用的'),
  ('disavow', 'v.', '否認、推翻', 'to deny responsibility for : REPUDIATE; to refuse to acknowledge or accept : DISCLAIM', 'The politician was quick to disavow any connection to the controversial statement. 這位政治人物迅速否認與這一具有爭議性的 聲明有任何關聯。', array['deny', 'disclaim', 'gainsay', 'negate', 'refute', 'reject', 'repudiate']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 49'),
  ('discern', 'v.', '（費力地）識別、看出', 'see clearly (with the senses or the mind), esp with an effort', 'discerned a figure approaching through the fog 察覺人影靠近', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
  ('disclaim', 'v.', '放棄、否認、拒絕承認', 'say that one does not have (sth); renounce', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 17 / 字根 claim, clam 喊、呼喊 / 提示 exclaim 驚叫、呼喊'),
