  ('eccentric', 'adj.', '古怪的、反常的', 'unusual; peculiar; not conventional or normal', 'an eccentric billionaire', array['bizarre', 'erratic']::text[], '{}'::text[], 'ec = ex 離開 + centric 中心', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 36'),
  ('eclectic', 'adj.', '折衷的、綜合性的', '(of people, beliefs, etc) not restricted to one source of ideas, etc, but choosing from or using a wide range', 'We appreciate the fact that he adopted an eclectic stance on this controversial issue. 我們欣賞他在這個有爭議性的議題上採取 兼容並蓄的立場 // the museum''s eclectic collection has everything from a giraffe skeleton to medieval musical instruments 綜合性的 收藏', array['heterogeneous']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 5'),
  ('eclipse', 'v.', '日蝕；月蝕 使黯然失色', 'to reduce in importance or repute // n. blocking of the light of the sun or of the moon (when the earth''s shadow falls on it)', 'The popularity of Internet led to the eclipse of the television programs.', array['outshine', 'outstrip', 'transcend']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 28'),
  ('ecstatic', 'adj.', '狂喜的、心花怒放的', 'causing or showing ecstasy', 'Ecstatic fans filled the stadium.', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 14'),
  ('edify', 'v.', '教化、訓誨', '(fml or joc ) improve the mind or character of (sb)', 'This speech was intended to edify the juveniles.', array['didactic (教化的)']::text[], '{}'::text[], 'edi = edu 教育(education)', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 32'),
  ('efface', 'v.', '擦掉、抹去 建築物的正面、（虛偽的）外表', 'rub or wipe (sth) out; cause to fade 1façade', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 28 / 字根 face 臉、面 / 提示 preface 序言、緒言'),
  ('efficacious', 'adj.', '有效的、靈驗的', '(not of people) producing the desired result; effective', 'The vaccine has proved both efficacious and safe. 這個疫苗被證明為很有效且安全的', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 21'),
  ('effrontery', 'n.', '厚顏無恥；魯莽', 'boldness or rudeness without shame; impertinence', 'He was silent all day had the effrontery to complain that I looked bored.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 38'),
  ('effusive', 'adj.', '熱情的、感情洋溢的', 'marked by the expression of great or excessive emotion or enthusiasm', 'The bride-to-be was effusive with gratitude for the outpouring of love and support from her family and friends. 這位未婚夫的新娘 對她的家人和朋友們的愛和支持洋溢著感激之情。', array['emotional', 'touchy-feely', 'uninhibited', 'unreserved', 'unrestrained']::text[], array['reticent(沈默的)']::text[], 'ef(=ex外) + fus流 → 感情流出的 → 熱情的', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 39'),
  ('egalitarian', null, '主張人人平等的', 'n, adj showing or holding a belief in equal rights, benefits and opportunities for everybody', 'There has always been a tension in the U.S. between our aspirations to national greatness and our egalitarian principles. - WSJ', '{}'::text[], '{}'::text[], 'ega = equ', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 27'),
