  ('emigrate', 'v.', '移居外國', '(to...) leave one''s own country to go and live in another', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 50 / 字根 migr 移動 / 提示 migration 移居、遷徙'),
  ('eminent', 'adj.', '出眾的、卓越的、著名的', 'famous and distinguished', 'Julian Huxley was an eminent biologist. — Angela Chen, The Verge', array['bright', 'distinguished', 'luminous']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 60'),
  ('emollient', null, '軟化劑、潤膚劑', 'n, adj that soothes and softens the skin', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 52 / 字根 moll 軟 / 提示 emollient 軟化劑、潤膚劑'),
  ('empathy', 'n.', '同理', 'ability to imagine and share another person''s feelings, experience, etc', 'Government officials must have empathy toward the disaster-stricken families. 政府關於必須對受災戶抱持同理心', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 22'),
  ('empiricism', 'n.', '經驗主義、經驗論', 'the practice of relying on observation and experiment especially in the natural sciences; a former school of medical practice founded on experience without the aid of science or theory', 'Rejecting evidence and empiricism is a step toward despotism. 拒絕證據和經驗主義是朝向專制主義的一步 // empirical data 經驗的數據 (data originating in or based on observation or experience)', '{}'::text[], '{}'::text[], 'empirical(經驗主義的、實驗主義的)', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 15'),
  ('empyrean', null, '天堂 (In ancient cosmologies, the Empyrean Heaven, or simply the Empyrean, was the place in the highest heaven, which was supposed to be occupied by the element of fire - wikipedia)', 'the apparent surface of the imaginary sphere on which celestial bodies appear to be projected', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 71 / 字根 pyr 火 / 提示 empyreal 天堂的'),
  ('emulate', 'v.', '效法、模仿', 'match or surpass (a person or achievement), typically by imitation', 'He tried to emulate Alexander the Great', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 17'),
  ('enact', 'v.', '制定（法律）、扮演（角色）', 'perform (a part, play, etc) on, or as if on, the stage of a theatre', 'The government plans to enact new laws to reduce pollution.', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 3 / 字根 act 行動 / 提示 activate 啟動'),
  ('enamored', 'adj.', '迷戀的', '(adj.) affected by strong feelings of love, admiration, or fascination', 'He would be enamored of a particular wine for a while, and then switch to a new one that caught his fancy. — Lisa King', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 35'),
  ('encapsulate', 'v.', '裝入膠囊；概括、摘要', 'sth (fml ) enclose sth (as if) in a capsule', 'the conclusion is encapsulated in one sentence', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 55'),
  ('encomium', 'n.', '誇獎、讚揚', '(fml ) very high praise in speech or writing', 'In his encomium for the retiring teacher, the principal praised her dedication and commitment to the students. 在對退休教師的頌詞 中，校長讚揚了她對學生的奉獻精神和承諾。', array['eulogy', 'panegyric(頌揚的)']::text[], array['diatribe(惡罵', '誹謗)']::text[], 'en(=in) + com(=come) → 進來讚揚', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 32'),
  ('encumber', null, '妨礙、拖累', 'to impede or hamper the function or activity of:HINDER', 'tourists encumbered by heavy luggage 被沉重行李拖累的觀光客 // negotiations encumbered by a lack of trust 因缺乏信任而受 阻礙的談判', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 16'),
  ('encyclopedic', 'adj.', '百科全書的、知識廣博的', 'dealing with or having knowledge of a wide variety of subjects; comprehensive', null, array['exhaustive 詳盡的']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 22 / 字根 cycl 圓、轉 / 提示 bicycle 腳踏車'),
  ('endemic', null, '地方性的、當地的', 'n, adj that is regularly found in a particular country or area, or among a particular group of people', 'the fish is not an endemic species of the lake 當地種; Malaria is endemic 地區性疾病 in hot, moist climates.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 37'),
  ('endorse', 'v.', '背書（在支票背面簽名）、贊同', 'to approve openly; write one''s name on the back of', 'The famous basketball player decided to endorse the new sports drink because he believed in its benefits. 這位著名的籃球運動員 決定代言這款新的運動飲料，因為他相信它的好處。', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 57'),
  ('endure', 'v.', '忍受、忍耐', 'suffer or undergo patiently', null, '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 37'),
  ('enervate', 'v.', '使失去活力、使衰弱', 'cause to lose strength or energy', 'A lifetime of working in dreary jobs had enervated his very soul.', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 61'),
  ('enfeeble', 'v.', '使虛弱、使無力', 'make weak or feeble', 'Some of these policies defy common economic sense 違反經濟學常識, and enfeeble India'' economy 虛弱印度的貨幣經濟', '{}'::text[], '{}'::text[], 'feeble 虛弱的', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 67'),
  ('enfetter', null, '束縛、上腳鐐', null, 'His soul is so enfettered to her love.', array['bind', 'chain', 'enchain', 'fetter', 'handcuff', 'manacle', 'shackle', 'trammel']::text[], '{}'::text[], 'en(使) + fetter(音讀「廢他」 → 使他成為廢人 → 上腳鐐、束縛', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 51'),
  ('engender', 'v.', '使產生、引起', 'to cause to exist or to develop : PRODUCE', 'policies that have engendered controversy 產生爭議的政策', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 6'),
  ('enigma', 'n.', '難以理解的事物、謎', 'question, person, thing, circumstance, etc that is difficult to understand; mystery', 'In the first half of the novel, Kilroy creates the enigma, which she proceeds to unravel (解開) in the second half.', array['conundrum']::text[], '{}'::text[], 'a. enigmatic (難以理解的 mysterious)', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
