  ('entail', 'v.', '(必然)伴隨著；意味著', 'to impose, involve, or imply as a necessary accompaniment or result', 'Buying a house can entail taking on a large amount of debt. 買房子可能需要承擔大量的債務。', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 67'),
  ('entice', 'v.', '引誘', 'sb (from sth); sb (into sth/doing sth) try to tempt or persuade sb, usu by offering sth pleasant or a reward', 'entice the customer into buying things they don''t really want', array['allure', 'bait', 'beguile', 'betray', 'decoy', 'lead on', 'lure', 'seduce', 'solicit', 'tempt']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 51'),
