  ('erudite', 'adj.', '博學的；知識豐富的', 'having or showing great learning; scholarly', 'He''s the author of an erudite book on Scottish history. 知識豐富的書的作者', '{}'::text[], '{}'::text[], 'e(出) + rud(無知) + ite → 走出無知', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 6'),
  ('escalate', 'v.', '升級、擴大；上升', 'increase or develop by successive stages; become or make (sth) more intense', 'An escalating trade war with China added to overall market woes. — Spencer Soper, The Seattle Times', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 45'),
  ('eschew', 'v.', '避開', 'keep away from (sth); abstain from; avoid', 'They eschew the simple title "professor" and call themselves economists and philosophers. 他們規避了教授這簡單的頭銜而稱呼 自己為經濟學者和哲學家', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
  ('esoteric', 'adj.', '圈內人才明白的、神秘難懂的', 'likely to be understood by only those with a special knowledge or interest; mysterious; obscure', 'He taught mathematics not as some esoteric mystery, but as practical common sense.', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 2'),
  ('espouse', 'v.', '支持、擁護', 'give one''s support to (a cause, theory, etc)', 'Lauren was criticized for espousing elite aspirations (志向；抱負), given his middle-class origins.', array['support', 'advocate']::text[], '{}'::text[], 'e + spouse(配偶)對於你做什麼事情都會支持擁護', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 32'),
  ('estrange', null, '使疏遠、使感情失和', 'to arouse especially mutual enmity or indifference in where there had formerly been love, affection, or friendliness:ALIENATE', 'The argument between the two friends caused them to estrange from each other. 這兩個朋友之間的爭執導致他們疏遠彼 此。', '{}'::text[], '{}'::text[], 'to strange', 1, 1, 'Mason 2000 / Mason 2000 PDF page 107 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('ethereal', 'adj.', '縹緲的、超凡的、精神的', 'of unearthly delicacy and lightness; seeming too spiritual or fairy-like for this world', null, '{}'::text[], '{}'::text[], 'e(=ex外) + the神 → 出神 → 虛無的、精神的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 86 / 字根 the 神 / 提示 atheist 無神論者'),
  ('ethos', 'n.', '道德風貌、思潮、信仰', 'characteristic spirit, moral values, ideas or beliefs of a group, community or culture', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 28 / 字根 ethn 種族 / 提示 ethics 倫理學、道德學'),
  ('eulogize', null, '稱讚、讚揚', 'to speak or write in high praise of:EXTOL', null, '{}'::text[], '{}'::text[], 'eu(好) + log(說) +ize', 1, 1, 'Mason 2000 / Mason 2000 PDF page 45 / 字根 locu, log, logu, loqu 說、言 / 提示 dialogue 對話'),
  ('eulogy', 'n.', '頌詞、頌文', '(speech or piece of writing containing) high praise of a person or thing', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 45 / 字根 locu, log, logu, loqu 說、言 / 提示 dialogue 對話'),
  ('euphemism', 'n.', '委婉的說法', 'use of pleasant, mild or indirect words or phrases in place of more accurate or direct ones', 'If you are "let go," "separated," "terminated" or whatever euphemism the company uses for "clean-out-your-desk-and-be-gone," remember that you do have rights.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 22'),
  ('euphoria', 'n.', '心情愉快；狂喜；興奮', 'intense feeling of happiness and pleasant excitement', 'As the initial euphoria wore off, so did the interest of potential investors. 隨著欣喜漸失，潛在投資人的興趣也漸散', '{}'::text[], '{}'::text[], 'eu(好) + phor(帶來) + ia', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 29'),
  ('evade', 'v.', '逃避、規避', 'get or keep out of the way of', 'The criminals have so far managed to evade the police.', '{}'::text[], '{}'::text[], 'e(出) + vad(走) -> 逃避', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 18'),
  ('evanescent', 'adj.', '逐漸消失的、短暫的', 'quickly fading; soon disappearing from memory', 'evanescent fame', array['ephemeral', 'transient', 'fugacious']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 18'),
  ('evasive', 'adj.', '迴避的、逃避的', 'having the aim or intention of avoiding capture, of not giving a direct answer, etc', 'She gave an evasive answer. 託辭', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 91 / 字根 vad, vas: to go, to walk 走 / 提示 invade 侵入、侵略'),
  ('evince', 'v.', '表明、顯示出', 'show clearly that one has (a feeling, quality, etc); exhibit', 'The data collected by the researchers evince a strong correlation between exercise and mental health. 這些研究人員所收集的數 據清楚地表明運動與心理健康之間有著強烈的相關性。', array['bespeak', 'betray', 'communicate', 'declare', 'demonstrate', 'display', 'expose', 'give away', 'manifest', 'reveal', 'show']::text[], '{}'::text[], 'evident (a)明顯的 evidence (n)證據', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 49'),
  ('evocative', null, '喚起的、激起的', 'bringing thoughts, memories, or feelings into the mind', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 96 / 字根 voc, vok 叫喊、聲音 / 提示 advocate 擁護、支持'),
  ('exacerbate', 'v.', '加重、惡化', 'make (pain, disease, a situation) worse; aggravate', 'The strong pound has exacerbated the situation by making it much harder for UK companies to compete on price. 英鎊走強使得英 國公司在價格上更難與他人競爭，使目前處境更加惡化', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
  ('exacting', 'adj.', '嚴格的、嚴厲的', 'making great demands; requiring great effort', 'The job required an exacting attention to detail and precision.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 16'),
  ('exactitude', 'n.', '正確性、精確性', 'the quality or an instance of being exact : EXACTNESS', 'The surgeon''s success relied on the exactitude of his movements.', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 54'),
  ('exalt', 'v.', '讚揚、歌頌', 'make (sb) higher in rank or greater in power', 'The retiring president was exalted by his colleagues.', array['extol', 'laud']::text[], array['lambaste(嚴厲指責)', 'pan(嚴厲批評)', 'deprecate(輕視', '抗議)', 'excoriate(批判)', 'disparage(藐視', '貶損)', 'vilify(誹謗)']::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 26'),
  ('exasperate', 'v.', '激怒、使惱怒', 'irritate or annoy greatly', 'It exasperated me that they never kept their promises. 他們從不遵守諾言令我惱火 // European officials are exasperated with Mr. Trump’s twitter threats. 川普推特威脅課歐洲關稅', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 34'),
  ('excavate', 'v.', '挖掘、挖出', 'make (a hole or channel) by digging; remove (soil, etc) by digging', 'It is the first site to be excavated in this area. 這是本區第一個被開挖的場所', array['dig', 'shovel']::text[], '{}'::text[], 'ex(外) + cav(洞) + ate', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 16'),
  ('exclaim', 'v.', '驚叫、呼喊', 'cry out suddenly and loudly from pain, anger, surprise, etc', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 17 / 字根 claim, clam 喊、呼喊 / 提示 exclaim 驚叫、呼喊'),
  ('exclamation', null, '驚嘆詞、驚呼', null, null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 17 / 字根 claim, clam 喊、呼喊 / 提示 exclaim 驚叫、呼喊'),
  ('excoriate', null, '痛責、剝（皮）', 'to censure scathingly', 'He excoriated the government for censorship. 他嚴厲譴責政府的審查制度', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 10'),
  ('excrete', 'v.', '排泄、分泌', '(of an animal or a plant) pass out (waste matter, sweat, etc) from the system', 'The kidneys excrete excess water and waste products from the blood. 腎臟從血液中排泄過剩的水和廢物。', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 56'),
  ('excruciate', null, '施酷刑、拷問、折磨', null, null, '{}'::text[], '{}'::text[], 'ex(完全地) + cruc(十字架) + iate → 在十字架上施酷刑 → 拷問、折磨', 5, 2, 'Mason 2000 / Mason 2000 PDF page 21 / 字根 cruc 十字、交叉 / 提示 cross 十字記號'),
  ('exculpate', 'v.', '開脫、申明無罪', 'sb (fml ) free sb from blame; say that sb is not guilty', 'The pilot of the aircraft will surely be exculpated.', '{}'::text[], '{}'::text[], 'ex(出) + culp(罪行) + ate', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 56'),
