  ('exhilarate', 'v.', '使振奮、使高興', 'make feel very happy or lively', 'The criminials were exhilarated by the news. 這消息令罪犯們很開心', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 28'),
  ('exigent', 'adj.', '緊急的、要求多的', 'requiring immediate action; urgent', '(1) The CEO was faced with an exigent decision regarding the company''s future. (2) exigent circumstances 緊急狀況', array['crititcal', 'acute']::text[], '{}'::text[], 'exit(出口) + ig(做、動) → 向出口衝 → 緊急的', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 12'),
  ('exiguous', 'adj.', '非常少的', 'very small (in amount); scanty', 'exiguous evidence', array['scanty', 'meager']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 51'),
  ('exodus', 'n.', '離開、湧離', '(to...) (fml or joc ) departure of many people at one time', 'The exodus of people from the city was caused by the outbreak of the pandemic. 人們從城市大量離開是由於疫情爆發所致。', '{}'::text[], '{}'::text[], 'Exodus《出埃及記》是聖經舊約的第二書，主要是講述以色列人如何在埃及受到逼害，然後由摩西帶領他們離開 埃及的故事。', 1, 1, 'Mason 2000 / Mason 2000 PDF page 107 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('exonerate', null, '免除責任、宣布無罪', 'to relieve of a responsibility, obligation, or hardship', 'The results of the DNA fingerprinting finally exonerated the man.', '{}'::text[], '{}'::text[], 'ex(免除) + oner(負擔) + ate', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 29'),
  ('exorbitant', 'adj.', '過分的、過度的', '(of a price, charge, etc) much too high or great; unreasonable', null, '{}'::text[], '{}'::text[], 'ex(超過) + orbit(常規) + ant', 1, 1, 'Mason 2000 / Mason 2000 PDF page 58 / 字根 orbit 軌道、常規 / 提示 orbit 軌道、常規'),
  ('exorcise', null, '驅魔、除去（壞念頭）', 'drive out evil spirits', 'exorcise demons from a young boy // communism was exorcised from the country', '{}'::text[], '{}'::text[], 'exo(出、外) + r + cise(切)', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 36'),
  ('expatriate', 'n.', '驅逐出國、脫離國籍', 'person living outside his own country', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 61 / 字根 patri 家長、國家 / 提示 patriot 愛國者、愛國主義者'),
  ('expedient', 'adj.', '方便的、權宜的', 'useful, helpful or advisable for a particular purpose, though not necessarily fair or moral', 'They found it expedient to negotiate with the terrorists. // Do the right thing, not the expedient thing.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 17'),
  ('expedite', 'v.', '促進﹐加快進程', 'help the progress of (work, business, etc); hasten or speed up', 'expedite the vaccine / expedite a visa', array['hasten']::text[], '{}'::text[], null, 4, 4, 'Mason 2000 / Mason 2000 PDF page 61 / 字根 ped 腳 / 提示 pedal 踏板、腳蹬'),
