  ('falsification', null, '竄改、編造、偽造', '[ falsify: ] vt. to make (a report, evidence, accounts, etc.) false or inaccurate by alteration, esp. in order to deceive', null, '{}'::text[], '{}'::text[], 'false 錯誤的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 29 / 字根 fall, fault 錯誤 / 提示 pitfall 陷阱、圈套'),
  ('fanatical', 'adj.', '狂熱的、盲信的', 'surpassing what is normal or accepted in enthusiasm for or belief in something; excessively or unusually dedicated or devoted', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 29 / 字根 fan 入迷、幻想 / 提示 fantasy 幻想、想像'),
