  ('fanfare', 'n.', '誇耀的遊行、嘹亮的喇叭聲', 'short ceremonial piece of music, usu played on trumpets', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 29 / 字根 fare 去 / 提示 farewell 辭行、告別'),
  ('fastidious', 'adj.', '挑剔的、過分講究的', 'selecting carefully; choosing only what is good', 'fastidious attention to detail 對於細節的挑剔關注', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 5'),
  ('fathom', 'n.', '噚（水深單位）、理解、了解原因', 'measure of the depth of water , 61.8; v. not capable of being fathomed: IMMEASURABLE, impossible to comprehend', 'He couldn''t fathom why his girlfriend was being so angry. 他無法理解他女朋友為何那樣生氣 // His behavior is completely unfathomable. 他的行為是完全無法被理解的', '{}'::text[], array['a. unfathomable 難以理解的', '高深莫測的']::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 11'),
  ('faux pas', null, '（外交）失禮、失言', null, 'I accidentally spilled my drink on my boss''s new suit at the company party, it was a terrible faux pas. 我在公司派對上不小心把 飲料灑在老闆的新西裝上，真是一個糟糕的失禮行為。', '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 107 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('fawn', 'v.', '搖尾乞憐、阿諛奉承', 'to court favor by a cringing or flattering manner n. deer less than one year old', 'The politician was surrounded by fawning supporters hoping to gain favor. 被阿諛的支持者包圍', array['flatter', 'kowtow']::text[], '{}'::text[], 'fans', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('feckless', 'adj.', '無效的、無能的', 'weak, ineffective; worthless, irresponsible', 'a well-intentioned but feckless response to the rise in school violence 對於校園暴力興起的一個動機良善卻無效的回應', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 16'),
  ('fecund', 'adj.', '肥沃、豐饒', 'fertile; productive', 'The fields were very fecund this year, yielding a record crop of wheat. 今年的農田非常肥沃，產出了創紀錄的小麥收成。', array['fertility']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('feign', 'v.', '假裝', 'pretend', 'feign death 假死 // He told the truth because he was no good at feigning 他不擅長掩飾事實因此說實話', array['dissemble', 'pretend']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 25'),
  ('felicific', null, '產生幸福的、帶來幸福的', null, 'the felicific effects of exercise 運動對幸福的促進作用', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 30 / 字根 felic 幸福 / 提示 felicitate 祝賀、慶祝'),
  ('felicitous', 'adj.', '（話語）得體的、適當的', '(esp of words) well-chosen; apt', 'Her felicitous choice of words made her speech a memorable one. 她妙筆生花的用詞使她的演講令人難忘。', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 58'),
  ('ferment', 'v.', '使發酵、醞釀', 'change chemically through the action of organic substances (esp yeast)', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 30 / 字根 ferv, ferm 熱 / 提示 fever 發燒'),
  ('ferocity', 'n.', '凶猛、激烈', 'fierceness; violence', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('ferromagnetic', null, '磁鐵的、鐵磁體的', null, null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 30 / 字根 ferr 鐵 / 提示 ferromagnetic 磁鐵的、鐵磁體的'),
  ('ferrous', null, '鐵的、含鐵的', null, null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 30 / 字根 ferr 鐵 / 提示 ferromagnetic 磁鐵的、鐵磁體的'),
  ('fervent', 'adj.', '炙熱的、熱情的', 'showing warmth and sincerity of feeling; enthusiastic; passionate', 'a fervent proponent 一個熱情的支持者', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 28'),
  ('fickle', 'adj.', '易變的、無常的', 'often changing; not constant', 'He blames poor sales on fickle consumers. 他將很差的銷售怪罪在善變的消費者', array['capricious', 'inconsistent', 'inconstant', 'mercurial', 'unpredictable', 'volatile']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 15'),
  ('fictitious', 'adj.', '假的、虛構的', 'imagined or invented; not real', 'fictitious company 不存在的、虛構的公司', '{}'::text[], '{}'::text[], '類似fiction → 小說是假的', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 58'),
  ('fidelity', 'n.', '忠實、忠誠', 'loyalty; faithfulness', 'his fidelity to liberal ideals 對自由派理念的忠誠', array['loyalty', 'faithfulness allegiance', 'ardor', 'devotion', 'fealty']::text[], array['unconventionality (異常)', 'apostasy (脫黨', '變節)']::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 21'),
  ('figurative', 'adj.', '比喻的、象徵', '(of words) used in an imaginative or a metaphorical way rather than literally', 'The phrase "raining cats and dogs" means literally "cats and dogs falling from the sky," while its figurative meaning is "heavy rain."', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 38'),
  ('filial', 'adj.', '子女的、孝順的', 'of or expected from a son or daughter', 'In Confucian, filial piety (孝) is a virtue of respect for one''s parents, elders, and ancestors.', '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 32 / 字根 fili 兒子 / 提示 affiliated 附屬的'),
  ('filter', 'n.', '濾器、過濾', 'device containing paper, sand, cloth, etc used to hold back any solid material or impurities in a liquid or gas passed through it', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 32 / 字根 filtr 過濾 / 提示 filter 濾器、過濾'),
  ('fine-tune', null, '進行微調', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 32 / 字根 fine 好、精緻 / 提示 fine 令人滿意的'),
  ('finesse', 'n.', '非凡的技巧、技術', 'skill in dealing with people or situations cleverly or tactfully', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 32 / 字根 fine 好、精緻 / 提示 fine 令人滿意的'),
  ('fiscal', 'adj.', '財政的、國庫的', 'of or related to government money or public money, usu taxes', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 32 / 字根 fisc 錢財 / 提示 fiscal 財政的、國庫的'),
  ('fitfully', null, '斷續的、不規則的', null, 'She slept fitfully throughout the night, waking up every few hours. 她整夜都睡得不安穩，每隔幾個小時就醒來一次。', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('fixate', null, '注視、使固定、使不便', 'stare at', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 32 / 字根 fix 固定 / 提示 fixate 注視、使固定'),
  ('flagged', null, '衰弱的', null, null, '{}'::text[], '{}'::text[], 'flagged(舉旗) → 衰弱所以投降舉旗 → 衰弱的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('flagrant', 'adj.', '惡名昭彰的、明目張膽的、公然的', 'particularly bad, shocking and obvious', null, array['notorious', 'egregious']::text[], '{}'::text[], null, 4, 4, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('flair', 'n.', '天賦、才華', 'for sth natural ability to do sth well', 'she had a flair for languages', array['aptitude', 'bent', 'endowment', 'faculty', 'genius', 'gift', 'head', 'knack', 'talent']::text[], '{}'::text[], '飛兒樂團', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 25'),
  ('flamboyant', 'adj.', '豔麗的、炫耀的', 'showy, very confident and extravagant', 'flamboyant blossoms', array['ornate']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 38'),
  ('flaunt', 'v.', '誇耀、炫耀', 'show (sth considered valuable) in order to gain the admiration of other people', 'She was flaunting her new car to make her neighbors jealous. 她炫耀她的新車來讓鄰居們嫉妒。', '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('fleeting', 'adj.', '轉瞬的、短暫的', 'passing quickly; lasting only a short time', 'Shore romances are often fleeting, but a lucky few couples make that love last.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('flippant', 'adj.', '輕率的、輕浮的、無禮的', 'not showing sufficient respect or seriousness', 'a flippant comment(無禮的評論)', array['cheeky', 'impertinent']::text[], array['solemn', 'sedate', 'sober', 'grave(嚴肅的)']::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('florid', 'adj.', '鮮紅色的、氣色好的、華麗的', 'elaborate and ornate; excessively decorated or colourful', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 33 / 字根 flor, flour 花 / 提示 flourish 昌盛、興旺'),
  ('flout', 'v.', '藐視、輕蔑、嘲笑', 'disobey openly and scornfully', 'flouting the rules / laws 輕蔑鄙視規則/法律', array['flaunt 炫耀', '賣弄 flaunt one''s success 炫耀…的成功']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 12'),
  ('fluctuate', 'v.', '波動、變動', '(of a price, number, rate, etc) rise and fall; change irregularly', 'Market liquidity can fluctuate throughout the day. 市場流動性一天來會有上下波動', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 19'),
  ('fluid', 'adj.', '流體的、流動的、易變的', 'able to flow freely, as gases and liquids do; not solid or rigid', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 33 / 字根 flu 流 / 提示 fluid 流體的、易變的'),
  ('flummery', null, '花言巧語；假恭維、胡說', 'a bland custard or pudding especially of oatmeal ; meaningless ceremonies and flattery', 'The salesman''s flummery didn''t fool me; I knew he was just trying to make a quick sale.', '{}'::text[], '{}'::text[], 'flower', 1, 1, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('foil', 'n.', '挫敗、阻擾、使受挫折；箔；陪襯', 'metal rolled or hammered into a very thin flexible sheet', 'She used humor to foil his attempt at an insult. 她使用幽默來挫敗他的侮辱企圖。', '{}'::text[], '{}'::text[], 'foil看似 fail (失敗) → 阻撓', 1, 1, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('foliage', 'n.', '葉子', 'leaves of a tree or plant; leaves with their stems and branches', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 33 / 字根 foli 樹葉 / 提示 foliage 葉子'),
  ('forage', 'v.', '糧草、搜尋、掠奪', 'to wander in search of forage or food // n. food for animals especially when taken by browsing or grazing', 'The cows were foraging in the pasture. 牛正在牧場尋覓食物', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 25'),
  ('forbear', null, '忍耐、抑制', null, 'forbore mentioning the incident 忍住不提那個事件', array['abstain (from)', 'forgo', 'keep (from)', 'refrain (from)', 'withhold (from) (n) forbearance']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 19'),
  ('forbid', 'v.', '禁止', 'order (sb) not to do sth', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 11 / 字根 bid 命令 / 提示 forbid 禁止'),
  ('forbidding', 'adj.', '可怕的（外貌）', 'looking unfriendly; stern; threatening', 'Notwithstanding its forbidding appearance, it is considered as an edible fish. 儘管看起來可怕，這是可以吃的魚', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 55'),
  ('forebode', 'v.', '預兆、預感', 'be a sign or a warning of (esp trouble)', null, array['foretell', 'portend']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 108 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('foreordain', null, '預先注定', 'in theology ; foreordain or determine beforehand', null, '{}'::text[], '{}'::text[], 'fore(=before先前) + ordain(命令) → 預先注定', 1, 1, 'Mason 2000 / Mason 2000 PDF page 58 / 字根 ord 命令 / 提示 order 命令'),
  ('foreshadow', 'v.', '預示、預兆', 'be a sign or warning of', 'Xi''s power play (權力遊戲；權力鬥爭) foreshadows historic transformation of how China is ruled.', array['presage', 'portend']::text[], '{}'::text[], 'fore(前) + shadow(影子) → 影子前來 → 預示物體即將到來', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('forestall', 'v.', '先發制人、預先阻止', 'act before so as to prevent him from doing sth', 'Vitamins may forestall many diseases of aging.', '{}'::text[], '{}'::text[], 'fore(前) + stall(站)→事先站在對方的路上→製造進攻犯規→先發制人', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 2'),
  ('forfeit', 'v.', '喪失、被罰沒收；作廢', 'lose or give up (sth) as a consequence of or punishment for having done sth wrong, or in order to achieve sth', 'When one of the ineligible 不合資格 players participated in a tournament game, the result was a forfeit.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 38'),
  ('forgo', 'v.', '放棄、拋棄', 'give up or do without (esp sth pleasant)', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 109 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('formative', 'adj.', '形成的、構成的', 'having an important and lasting influence on the development of sb''s character', 'formative years: 人格、個性形塑之年', array['n. formulation 規劃', '構想', '公式化']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 21'),
  ('formidable', 'adj.', '可怕的、令人畏懼的；令人敬畏的', 'causing fear or great anxiety; frightening; awesome', 'The mountains were a formidable barrier. // He has mastered a formidable amount of material.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 19'),
  ('formulaic', null, '公式的、刻板的', null, null, '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 38'),
  ('fort', 'n.', '要塞、堡壘', 'Building specially made or strengthened for the military defence of an area', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 34 / 字根 fort 強壯 / 提示 fort 要塞、堡壘'),
  ('forte', 'n.', '長處、擅長的事；（音樂）強', 'thing that sb does particularly well; strong point', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 34 / 字根 fort 強壯 / 提示 fort 要塞、堡壘'),
  ('forthright', 'adj.', '直接的', 'clear and honest in manner and speech; straightforward', null, '{}'::text[], '{}'::text[], 'forth 向前的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 109 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的');
