  ('fortify', 'v.', '增強、加強', 'sth (against sth) strengthen (a place) against attack, by building walls, etc', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 34 / 字根 fort 強壯 / 提示 fort 要塞、堡壘'),
  ('fortuitous', 'adj.', '偶然的；幸運的', 'happening by chance or coincidence; FORTUNATE, LUCKY', 'hiring seems all the more uncertain if not fortuitous. 雇人若不能說全是運氣，也顯得非常不確定', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('foster', 'v.', '促進、鼓勵、養育', 'help the growth or development of (sth); encourage or promote', 'We''re trying to foster a sense of responsibility. 培養責任感', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 51'),
  ('founder', 'v.', '沉沒、失敗、破滅', ': to become disabled; especially : to go lame; to give way : COLLAPSE; to become submerged : SINK', 'Her career foundered, and she moved from job to job for several years.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 39'),
  ('fraction', 'n.', '碎片、小部分', 'small part, bit, amount, or proportion', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 34 / 字根 frac, fract, frag 碎裂 / 提示 fragment 碎片、分裂'),
  ('fractious', 'adj.', '（脾氣）易怒的、好爭吵的', 'irritable; bad-tempered', 'They fight and squabble like fractious children.', '{}'::text[], '{}'::text[], '玻璃心', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 38'),
