  ('immutable', 'adj.', '不變的', 'that cannot be changed; that will never change', 'Some people regard grammar as an immutable set of rules. 有些人認為文法是一套不可更改的規則', array['fixed', 'hard-and-fast', 'inalterable', 'incommutable', 'invariable', 'unalterable']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 60'),
