  ('impassioned', 'adj.', '充滿激情的、慷慨激昂的、熱烈的', 'showing strong deep feeling', 'Her lawyer made an impassioned argument in her defense. 她的律師慷慨激昂地陳述辯護詞語', array['a. impassionate 充滿熱情的 fervent', 'vehement']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 17'),
  ('impassive', 'adj.', '不露情感的、無動於衷的、冷漠的', 'showing no sign of feeling', 'In the executive boxes, even Russia''s president, Vladimir V. Putin, ordinarily so impassive, twitched the corners of his mouth in what could, just about, be recognized as a smile. -New York Times (2018世界盃開幕戰，俄羅斯以5：0大勝沙烏地阿拉伯)', array['apathetic', 'numb']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 61'),
  ('impeachable', null, '可指責的', null, 'Sara was raised by a single mother who, before dying young, gave her pretty unimpeachable advice: Never depend on a man. — Glen David Gold, New York Times', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 52'),
