  ('impertinent', 'adj.', '粗魯無禮的、不切題的、不中肯的', 'not respectful; rude', 'She asked a few impertinent questions. // the impertinent child had a smart answer for everything', array['insolent', 'impudent']::text[], '{}'::text[], 'im(不) + pertinent(恰當的) → 不恰當的 → 言行無禮的', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 47'),
  ('imperturbable', 'adj.', '冷靜的、沈著的', 'not easily troubled or worried; calm', 'The chef was absolutely imperturbable—even when the kitchen caught on fire.', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 64'),
  ('impervious', 'adj.', '不受影響的、無動於衷的', 'not allowing water, gas, etc to pass through', 'Despite the glibness of his tongue, I am still impervious to his persuasion. 儘管他說得天花亂墜，我還是對他的說法無動於衷 // He is impervious to criticism. 他不為批評所動', array['immune to', 'invulnerable to', 'insusceptible to']::text[], '{}'::text[], 'im(不) + pervi(音讀「潑」 → 不受被潑影響 → 不受影響的', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 65'),
  ('impetuous', 'adj.', '性急的、魯莽的、衝動的', 'acting or done quickly and with little thought or care; rash or impulsive', 'an impetuous temperament 衝動的性情', '{}'::text[], '{}'::text[], 'im 加強語氣 + pet 追求 → 魯莽的、衝動的', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 13'),
  ('impetus', 'n.', '推動力、刺激', 'thing that encourages a process to develop more quickly', 'The reward money should be sufficient impetus for someone to come forward with information about the robbery.', array['boost', 'impulse', 'incentive', 'motivation', 'provocation', 'spur', 'stimulus']::text[], '{}'::text[], 'im 加強語氣 + pet 追求', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 42'),
  ('implacable', 'adj.', '不能安撫的、難和解的', 'that cannot be changed or satisfied', 'He has an implacable hatred for his political opponents. 他對於他的政敵有難和解的仇恨', array['adamant', 'obstinate']::text[], array['acquiescent', 'amenable', 'pliant', 'relenting']::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 17'),
  ('implausible', 'adj.', '難以置信的、不像真實的', 'unlikely to be true; not convincing', 'This is a blatantly implausible claim. 這是明顯扯翻的主張', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 22'),
