  ('ingest', 'v.', '嚥下、吞下', 'take (food, etc) into the body, typically by swallowing', null, '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 39'),
  ('ingrain', null, '使…根深蒂固', null, 'I simply have this ingrained aversion 根深蒂固的厭惡 to the sight of bloodshed. // While Canada prides itself on embracing immigrants, the (far-right) group (將伊斯蘭族群視為威脅的極右派社群) has resonated with a small but vocal minority in Quebec, where a strong tradition of secularism (世俗主義) was ingrained during a revolt against the Roman Catholic Church in the 1960s. — Dan Bilefsky, New York Times * 世俗主義是一種在社會生活和政治活動中，擺脫宗教組織控制的主張。', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 39'),
  ('ingrate', null, '忘恩負義的人', 'ungrateful person', null, '{}'::text[], '{}'::text[], 'in(不) + grat(感激) + e', 1, 1, 'Mason 2000 / Mason 2000 PDF page 38 / 字根 grat 感激 / 提示 grateful 感謝的、感激的'),
  ('ingratiate', 'v.', '使得到…歡心、迎合', 'to gain favor or favorable acceptance for by deliberate effort —usually used with with; to become popular with', 'ingratiate himself with his boss 討好老闆', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 34'),
  ('ingratiating', 'adj.', '討好的、諂媚的', 'attempting to please, flatter or gain favour', 'The waiter ignored me as I smiled and tried not to look too ingratiating.', array['endearing', 'flattering']::text[], '{}'::text[], 'in(加強語氣) + grat(感激) → 不停感激的 → 諂媚討好的', 3, 3, 'Mason 2000 / Mason 2000 PDF page 38 / 字根 grat 感激 / 提示 grateful 感謝的、感激的'),
