  ('leaven', 'n.', '酵母、使有趣活潑', 'substance used to make dough rise before it is baked to make bread', 'a speech leavened with humor', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 44 / 字根 lev 舉、升、使…輕 / 提示 elevator 電梯'),
  ('legislature', 'n.', '立法機關', 'body of people with the power to make and change laws', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 43 / 字根 leg 法律 / 提示 legal 合法的'),
  ('legitimate', 'adj.', '合法的、正當的', 'in accordance with the law or rules; lawful', 'a legitimate government; legitimate means', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 40'),
  ('lethal', 'adj.', '致命的、危險的', 'causing or able to cause death', 'Israel has been widely criticized for using lethal force against largely unarmed protesters. — NBC News', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 52'),
  ('lethargic', 'adj.', '瞌睡的、愛睡的', 'feeling a lack of energy or a lack of interest in doing things', 'I have been quite lethargic lately under the influence of the medicine,. 在藥物的影響下，我近來很嗜睡', array['somnolent']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 12'),
  ('levity', 'n.', '幽默；輕率、輕浮', 'lack of proper seriousness or respect', 'His comments injected some much-needed levity into the otherwise tense meeting. 他的評論為本來緊張的會議注入了一些必 要的幽默感。', array['facetiousness', 'flippancy', 'frivolousness', 'light-headedness']::text[], '{}'::text[], 'lev 升 e.g. elevate', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 59'),
  ('liberal', 'adj.', '自由派的；慷慨的', 'of or constituting a political party advocating or associated with the principles of political liberalism', 'a liberal giver', '{}'::text[], array['illiberal', 'stingy']::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 44 / 字根 liber 自由 / 提示 liberal 自由派的、慷慨的'),
  ('limpid', 'adj.', '清澈的、透明的', 'clear; transparent', 'limpid prose', array['pellucid']::text[], array['murky(陰暗的)']::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 113 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('lionize', 'v.', 'v. 視為上賓、視為重要人物', 'assign great social importance to', 'She was lionized everywhere after her novel won the Pulitzer Prize.', '{}'::text[], '{}'::text[], 'lion為正面形象(獅子王辛巴)，變為獅子即捧為上賓', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 19');
