  ('lopsided', null, '傾向一邊的、不平衡的；一面倒的', null, 'Pitt topples Maryland Eastern Shore in lopsided win.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('loquacious', 'adj.', '多話的、非常健談的', 'fond of talking; talkative', 'The typically loquacious Cruz went silent for a remarkable 18 seconds. 平常總健談的Cruz沉默了整整18秒', array['garrulous', 'talkative']::text[], array['laconic', 'reticent', 'taciturn']::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 10'),
  ('lucid', 'adj.', '清楚易懂的、明晰的', 'clearly expressed; easy to understand', 'write in a clear and lucid style.', array['distinct', 'evident', 'lucid', 'manifest', 'pellucid', 'plain']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 4'),
  ('lucrative', 'adj.', '賺錢的、有利可圖的', 'producing much money; profitable', 'After three years in the business, they found out that running a book store was not as lucrative as they thought. 做了三年之後，他們 才發現開書店並沒有他們想像的那麼好賺', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 13'),
  ('lucubration', null, '苦心研究', 'a solemn literary work that is the product of laborious cogitation ; laborious cogitation', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 46 / 字根 luc: light 光 / 提示 luxury 奢華'),
  ('ludicrous', 'adj.', '滑稽的、荒唐可笑的', 'causing laughter; ridiculous; absurd', 'For him (Dark Knight''s Joker), humans are ludicrous creatures 黑暗騎士內的小丑，覺得人類是個可笑的生物', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 40'),
  ('lugubrious', 'adj.', '悲傷的（尤指誇張地）、憂鬱的', 'dismal; mournful', 'his face looked even more lugubrious than usual 他的臉顯得比平常更加憂鬱悲傷', '{}'::text[], '{}'::text[], 'lugu音讀「露骨」 → 骨折露骨 → 悲傷的', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 9'),
  ('lull', 'v.', '使入睡、暫停', 'sb/sth (to sth) make (a person or an animal) quiet or less active; soothe sb/sth', null, '{}'::text[], '{}'::text[], 'lullaby', 1, 1, 'Mason 2000 / Mason 2000 PDF page 113 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('luminary', 'n.', '傑出人物、才智出眾的人', 'person who inspires or influences others', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 47 / 字根 lumin 光 / 提示 illuminate 闡明、解釋、照亮'),
  ('lunar', null, '月的、月球上的', null, null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 47 / 字根 lun 月亮 / 提示 lunar 月的、月球上的'),
  ('lunatic', 'n.', '瘋子、瘋傻的人', 'insane person', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 47 / 字根 lun 月亮 / 提示 lunar 月的、月球上的'),
  ('lurid', 'adj.', '聳人聽聞的、可怕的', 'MELODRAMATIC, SENSATIONAL; SHOCKING; having bright glaring colours or combinations of colour', 'Spare me the lurid details of the murder; just make sure that he is the murderer. 你不用告訴我謀殺案的可怕的細節；只要確 定他是凶手就足夠了。', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 9'),
  ('lust', 'n.', '有強烈慾望、貪戀', '(for sb) strong sexual desire', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 47 / 字根 lust 有強烈慾望、貪戀 / 提示 lust 有強烈慾望、貪戀'),
  ('luxuriant', 'adj.', '繁茂的、肥沃的', 'growing thickly and strongly; lush', 'a luxuriant beard 濃密的鬍鬚 // luxuriant soil 肥沃的土地 // Luxuriant forests covered the hills. 山丘上長滿茂密的樹木', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 22'),
  ('magnanimous', 'adj.', '寬大的、有雅量的', 'having or showing great generosity', 'Before I was abrasive 粗魯無禮的, but now I have learned the art of becoming more magnanimous. 寬大的', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 8'),
  ('magnitude', 'n.', '重大、廣大', '(usu large) size', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 47 / 字根 magn 大 / 提示 magnificent 壯麗的'),
  ('maintain', 'v.', '堅持、主張；維護、維持', 'to affirm in or as if in argument : ASSERT', 'He maintains that he once saw a UFO.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 47'),
  ('maladroit', 'adj.', '笨拙的', 'not clever or skilful; clumsy; bungling', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 26 / 字根 droit 右邊、擅長 / 提示 adroit 靈巧的、熟練的'),
  ('malady', null, '病、疾病', null, 'told by his physicians that he had a fatal (致命的) malady — Willa Cather', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 40'),
  ('malapropism', null, '文字誤用', 'ncomical confusion of a word with another, similar-sounding,word which has a quite different meaning, eg `an ingenuousmachine for peeling potatoes''', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 70 / 字根 prop 挪用、適當、恰當 / 提示 appropriate 適當的、挪用'),
  ('malediction', 'n.', '詛咒、壞話', 'prayer that sb or sth may be destroyed, hurt, etc; curse', null, '{}'::text[], '{}'::text[], 'male(壞) + dict(說話) + ion', 1, 1, 'Mason 2000 / Mason 2000 PDF page 24 / 字根 dic, dict 說話、命令 / 提示 predict 預測'),
  ('maleficent', 'adj.', '有害的、犯罪的', 'causing or doing evil', null, '{}'::text[], '{}'::text[], '黑魔女 | male(壞) + foc(做) + ent', 5, 2, 'Mason 2000 / Mason 2000 PDF page 31 / 字根 fec, fic, fict: to do 做 / 提示 deficient 有缺陷的、不足的'),
  ('malevolent', 'adj.', '有惡意的、惡毒的', 'wishing to do evil or cause harm to others; spiteful', 'malevolent villains', array['malicious', 'malign', 'vicious', 'virulent']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 40'),
  ('malfeasance', null, '不法行為、瀆職', 'a wrongful act that the actor had no right to do; improper professional conduct', 'The company fired the CEO for malfeasance after he was found guilty of insider trading. 公司因行為不當解雇了CEO，他因內 幕交易被判有罪。', array['misbehavior', 'misconduct', 'wrongdoing']::text[], '{}'::text[], 'mal(壞) + feas(做) + ance', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 57'),
  ('malign', 'v.', 'adj. 惡意的 v. 誹謗', 'say unpleasant or untrue things about; to utter injuriously misleading or false reports about : speak evil of', 'had a malign influence on 有不良影響; a malign industry 邪惡產業', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 59'),
  ('malinger', 'v.', '裝病', 'to pretend or exaggerate incapacity or illness (as to avoid duty or work)', 'He was suspected of malinger ing to avoid work, but it turned out that he was genuinely ill. 他被懷疑裝病逃避工作，但事實證 明他真的病了。', '{}'::text[], '{}'::text[], '沒人格', 1, 1, 'Mason 2000 / Mason 2000 PDF page 113 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('malleable', 'adj.', '可塑的、展延的', 'that can be beaten or pressed into different shapes easily', 'Digital technology is the most malleable resource at the world’s disposal to overcome constraints - Microsoft CEO Satya Nadella', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('malodorous', 'adj.', '惡臭的', 'smelling unpleasant', 'the malodorous smell', array['fetid', 'foul', 'noisome', 'reeking', 'reeky', 'ripe', 'smelly', 'stinky', 'strong']::text[], '{}'::text[], 'male(壞) + odor(氣味) + ous', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 61'),
  ('mandate', 'n.', '命令、指令；授權 a. mandatory 命令的、牆破的', 'an authoritative command; (to do sth) authority given to a party, trade union, etc by the people who support it', 'They carried out the governor''s mandate to build more roads. 他們執行政府的指令蓋更多路 // He won the election so overwhelmingly that he believed he had been given a mandate for change. 他贏得選戰是如此的壓倒性的，使得他相信他被授權 做改變', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 17'),
  ('mandatory', 'adj.', '命令的、強迫的', 'required by law; compulsory', 'the mandatory retirement age 強制退休年齡', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 17'),
  ('maneuver', null, '（部隊）調動、機動', '= manoeuvre', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 47 / 字根 man, manu 手 / 提示 manual 手冊'),
  ('mania', 'n.', '瘋狂、狂熱', 'mental disorder marked by extreme excitement or violence', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 48 / 字根 mania 狂熱 / 提示 monomania 偏執狂、狂熱病'),
  ('manifest', 'adj.', '明顯的、顯而易見的', '(fml ) clear and obvious', 'His love for literature is manifest in his large library.', array['obvious', 'apparent']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 113 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('manipulate', 'v.', '（熟練地）操作、運用', 'control or handle with skill; to control or play upon by artful, unfair, or insidious means especially to one''s own advantage', 'a blatant attempt 公然的明顯的嘗試 to manipulate public opinion', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 40'),
  ('manuscript', 'n.', '手寫的、原稿的', 'thing written by hand, not typed or printed', null, '{}'::text[], '{}'::text[], 'manu(手) + script(寫)', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 59'),
  ('mar', 'v.', '毀損、損傷、玷汙', 'damage (sth); spoil', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 48 / 字根 mar 毀壞 / 提示 martial 戰爭的、軍事的'),
  ('marine', 'adj.', '海的、海中的', 'of, near, found in or produced by the sea', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 48 / 字根 mari 海 / 提示 marine 海的、海中的'),
