  ('martial', 'adj.', '戰爭的、軍事的', 'of or associated with war', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 48 / 字根 mar 毀壞 / 提示 martial 戰爭的、軍事的'),
  ('mawkish', 'adj.', '過度感傷的、多愁善感的', 'sentimental in a feeble or sickly way', 'The movie''s mawkish ending was criticized for being overly sentimental and unrealistic. 這部電影過於感傷的結局被批評為過 分情緒化和不現實。', '{}'::text[], '{}'::text[], '音讀「馬克」 → 時常靠腰 → 過度感傷的、多愁善感的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 113 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('meager', null, '瘦的、粗劣的、不足的', 'deficient in quality or quantity', 'meabusiness investmen grew at a meager 0.8% annual rate 商業投資僅成長0.8%; He could not support his family on his meager salary. 他靠微薄的薪資無法養家', array['insufficient 不足的', '不夠的']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 67'),
  ('meander', 'v.', '迂迴曲折、閒晃、漫步', 'follow a winding course, flowing slowly', 'a leisurely meander 悠閒的漫步', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 114 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('measured', 'adj.', '慎重的', '(of speech or writing) carefully considered and restrained (嚴謹的、克制的)', 'his measured prose', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 2000 / Mason 2000 PDF page 50 / 字根 mens 測量 / 提示 measure 測量'),
  ('mediate', 'v.', '調停解決', 'act as a peacemaker or go-between for two or more people, groups, etc who disagree', 'These students were unwilling to be mediated and mollified 緩和，平息 by spokespeople or television anchors. — Lara Backmender, Glamour', array['intercede', 'intermediate', 'interpose', 'intervene']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 59'),
  ('medieval', 'adj.', '中世紀的、中古的', 'of the Middle Ages, about AD 1100-1400 , 1100-1400', null, '{}'::text[], '{}'::text[], 'medi(中) + ev(時代) + al', 2, 1, 'Mason 2000 / Mason 2000 PDF page 28 / 字根 ev 年齡、時代 / 提示 medieval 中世紀的、中古的'),
  ('mediocre', 'adj.', '平凡的、平庸的', 'not very good; second-rate', 'the acting is mediocre. 演技平庸', array['common']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 10'),
  ('meditate', 'v.', '沉思、深思熟慮；冥想', 'think deeply about (something)', 'they began to meditate retreat 開始仔細考慮要撤退', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 2000 / Mason 2000 PDF page 49 / 字根 medita: to ponder 思考 / 提示 meditate 沉思、冥想'),
  ('meditation', 'n.', '沉思、默想；冥想', 'deep thought, esp about spiritual matters', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 49 / 字根 medita: to ponder 思考 / 提示 meditate 沉思、冥想'),
  ('melancholy', 'n.', '憂鬱；憂思；憂鬱的', 'deep sadness which lasts for some time; depression', 'sang in a melancholy voice', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 2000 / Mason 2000 PDF page 114 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('mellifluous', 'adj.', '聲音甜美的; 悅耳的﹐動聽的', 'sweet-sounding; (almost) musical', null, '{}'::text[], '{}'::text[], 'melli(蜂蜜) + flu(流) + ous → 流蜜的 → 柔美流暢的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 33 / 字根 flu 流 / 提示 fluid 流體的、易變的'),
  ('memoir', null, '回憶錄、自傳', null, null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 49 / 字根 memor 記住 / 提示 memory 記憶'),
