  ('peripheral', 'adj.', '不重要的；外圍的、周邊的、邊緣的', 'of secondary or minor importance (to sth)', 'If we focus too much on peripheral issues, we will lose sight of the goal. 若我們太過關注邊緣議題，我們就會對目標失焦 peripheral devices such as modems and scanners 諸如數據機和掃描器的周邊設備', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 13'),
  ('permeate', 'v.', '滲入、通過', 'sth (fml ) enter sth and spread to every part', 'a permeable membrane 能穿透的膜', array['penetrate', 'permeable = porous']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 116 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('pernicious', 'adj.', '有毒的、致命的', '(to sb/sth) having a very harmful or destructive effect (on sb/sth)', 'the pernicious effects of jealousy 忌妒的致命效果', '{}'::text[], '{}'::text[], 'per(完全) + nic(毒) + ious', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 41'),
  ('perpetuate', 'v.', '使永存不朽、使不朽', 'cause to continue', 'Fears about an epidemic are being perpetuated by the media. 媒體延續了對於流行病的恐懼', '{}'::text[], '{}'::text[], 'per(全部) + (pet追求) → 使大家都可以追求 → 永垂不朽', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 11'),
  ('perquisite', 'n.', '額外補貼、臨時津貼', '(fml ) (infml perk) money or goods given or regarded as a right in addition to one''s pay', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 116 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('persecute', null, '迫害、殘害', 'subject (someone) to hostility and ill-treatment, especially because of their race or political or religious beliefs；harass or annoy (someone) persistently', 'A report has revealed the shocking extent of violence and persecution faced by LGBT+ people in Myanmar.', '{}'::text[], '{}'::text[], 'per(始終) + secu(跟隨) + te → 一直跟蹤 → 迫害', 3, 3, 'Mason 2000 / Mason 2000 PDF page 77 / 字根 secu 跟隨 / 提示 consecutive 連續不斷的'),
  ('persistent', 'adj.', '堅持不懈的；持續的', 'refusing to give up; continuing without change in function or structure', 'a persistent salesman 一個持續不懈的銷售員 // There''s been persistent political and law enforcement dysfunction in Baltimore 有 持續的政治和執法上的運作不良', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 25'),
  ('personification', 'n.', '典型、化身、完美榜樣', 'treating sth that is without life as a human being or representing it in human form', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 63 / 字根 person 人 / 提示 person 人'),
  ('perspicuous', 'adj.', '明晰的、明瞭的', 'expressed clearly', 'The president began his Monday by scrutinizing (仔細鑽研；仔細檢查) his national security briefing, filling its margins (邊緣；餘 地) with perspicuous questions and observations. — Eric Levitz, Daily Intelligencer', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 63'),
  ('perspire', 'v.', '流汗、辛勞', 'give off moisture through the skin; sweat', null, '{}'::text[], '{}'::text[], 'per(完全) + spire(呼吸) → 全身呼吸 → 流汗', 5, 2, 'Mason 2000 / Mason 2000 PDF page 81 / 字根 spir 呼吸 / 提示 perspire 流汗、辛勞'),
  ('pertain', 'v.', '屬於、關於', 'to sth (used esp in the continuous tenses ) be connected with or relevant to sth', 'books pertaining to our country''s history 與本國歷史有關的書籍', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 24'),
  ('pertinent', 'adj.', '有關的、相關的', '(fml ) relevant (to sth); to the point', 'He impressed the jury with his concise, pertinent answers to the attorney''s questions.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 2000 / Mason 2000 PDF page 84 / 字根 tain, ten, tin 保持、維持、抓住 / 提示 contain 包含、容納'),
  ('pervade', 'v.', '瀰漫、普及', 'spread to and be perceived in every part of', 'A feeling of great sadness pervades the film.', '{}'::text[], '{}'::text[], 'per(完全) + vad(走) + e → 走遍', 1, 1, 'Mason 2000 / Mason 2000 PDF page 91 / 字根 vad, vas: to go, to walk 走 / 提示 invade 侵入、侵略'),
  ('pervasive', 'adj.', '瀰漫的、遍佈的', 'present and perceived everywhere; pervading', 'television''s pervasive influence on our culture', '{}'::text[], '{}'::text[], 'per(完全) + vad(走) + e → 走遍', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 5'),
  ('perverse', 'adj.', '故意作對的；走上邪路的、墮落的、邪惡的', '(of a person) deliberately continuing to behave in a way that is wrong, unreasonable or unacceptable', 'The child''s perverse behavior was a result of his rebellious nature. 那個孩子的任性行為是他反叛性格的結果。', '{}'::text[], '{}'::text[], 'pervert 行為反常者；墮落者', 1, 1, 'Mason 2000 / Mason 2000 PDF page 93 / 字根 vert, vers 轉 / 提示 reverse 倒車、反轉'),
  ('pesticide', 'n.', '殺蟲劑', 'chemical substance used to kill pests, esp insects', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 16 / 字根 cide, cise 殺、切、切割 / 提示 concise 簡潔的'),
  ('petition', 'n.', '請願、請願書', 'formal written request, esp one signed by many people appealing to sb in authority', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 63 / 字根 pet: seek 追求 / 提示 repeat 重說、重寫'),
  ('petrify', null, '石化、嚇呆', 'take away power to feel through terror; turn to stone', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 63 / 字根 petro 石頭 / 提示 petroleum 石油'),
  ('petroglyph', null, '岩石畫、岩石雕刻', null, null, '{}'::text[], '{}'::text[], 'petro(石頭) + glyph(寫、刻)', 5, 2, 'Mason 2000 / Mason 2000 PDF page 37 / 字根 glyph 寫、刻 / 提示 petroglyph 岩石畫'),
  ('petroleum', 'n.', '石油', 'mineral oil that forms underground and is obtained from wells sunk into the ground, from which petrol, paraffin, diesel oil, etc are obtained by processing', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 63 / 字根 petro 石頭 / 提示 petroleum 石油'),
  ('petulant', 'adj.', '暴躁的、壞脾氣的', 'unreasonably impatient or irritable', 'Trump himself looks like a comically petulant child, and John Bolton, the National Security Advisor, appears to be nervous, staunchly standing by the president. - Meagan Fredette, refinery29.com', array['peevish']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('philanthropic', 'adj.', '博愛的、仁慈的、慈善的', 'of or inspired by philanthropy', null, '{}'::text[], '{}'::text[], 'phil(愛) + anthrop(人)', 1, 1, 'Mason 2000 / Mason 2000 PDF page 7 / 字根 anthrop 人 / 提示 anthropology 人類學'),
  ('philistine', 'n.', '庸俗的人；不懂藝術的人、沒有教養的人', 'person who has no interest in or understanding of the arts, or is hostile to them; uncultured person', 'It is a fact of philistine life that amusement is where the money is. — William H. Gass', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('philosophic', null, '哲學的、哲學家的', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 80 / 字根 soph 智慧 / 提示 sophomore 大二'),
  ('phlegmatic', 'adj.', '冷靜的、沉着的', 'calm and even-tempered; showing the quality of phlegm', 'phlegmatic attitude 冷靜的態度', array['apathetic', 'impassive', 'numb', 'stoic']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('phobia', 'n.', '恐懼症、懼怕', 'extreme or abnormal dislike or fear of sth; aversion', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 64 / 字根 phob 憎恨 / 提示 phobia 恐懼症、懼怕'),
  ('phony', null, '假的、欺騙的', 'fraudulent; having a misleading appearance ; a person who professes beliefs and opinions that they do not hold', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 64 / 字根 phon: sound 聲音 / 提示 phonetic 發音的、語音的');
