  ('photosensitive', null, '感光的', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 64 / 字根 photo 光 / 提示 photosynthesis 光合作用'),
  ('photosynthesis', 'n.', '光合作用', 'process by which green plants convert carbon dioxide and water into food using the energy in sunlight', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 64 / 字根 photo 光 / 提示 photosynthesis 光合作用'),
