  ('picturesque', null, '圖畫般的、美麗的', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 64 / 字根 pict 描繪 / 提示 depict 描繪'),
  ('piety', 'n.', '虔誠', 'devotion to God and respect for religious principles; being pious', 'filial piety (孝順) || Her piety is evident in her regular attendance at church and involvement in charitable activities. 她的虔誠在她 定期參加教會活動和參與慈善事業上表現得淋漓盡致。', '{}'::text[], '{}'::text[], 'In Confucian and Chinese Buddhist ethics, filial piety (孝) is a virtue of respect for one''s parents, elders, and ancestors.', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 43'),
  ('pigeonhole', null, '鴿舍出入口、分類', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 116 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('pilferage', null, '偷竊、竊盜行為', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 116 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('pine', 'n.', '松樹', '(also `pine tree) any of several types of evergreen tree that bear cones and have needle-shaped leaves growing in clusters', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 65 / 字根 pin 針 / 提示 pinpoint 針尖、準確地確定'),
  ('pinnacle', 'n.', '小尖塔、尖頂', 'small pointed ornament built on to a roof or buttress', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 65 / 字根 pin 針 / 提示 pinpoint 針尖、準確地確定'),
  ('pinpoint', 'n.', '針尖、準確地確定', 'sharp end of a pin', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 65 / 字根 pin 針 / 提示 pinpoint 針尖、準確地確定'),
  ('pious', 'adj.', '虔誠的、盡責的', 'having or showing a deep devotion to religion', 'The pious man spent hours each day in prayer and meditation. 虔誠的人每天花費數小時進行祈禱和冥想。', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('pitfall', 'n.', '陷阱、圈套', 'unsuspected danger or difficulty', null, '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 37'),
  ('placate', 'v.', '撫慰、平息；緩和；讓步妥協', 'make less angry; soothe or pacify', 'In an attempt to avoid conflict, she tried to placate her upset colleague by apologizing. 為了避免衝突，她試圖通過道歉來安撫 心情不好的同事。', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 43'),
  ('placebo', 'n.', '安慰劑、寬心丸', '(medical ) harmless substance given as if it were medicine to calm a patient who mistakenly believes he is ill', 'More than 240 participants were split into two groups — one was given single doses of a topical testosterone gel, while the other was given placebo. — Sy Mukherjee, Fortune', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('placid', 'adj.', '安靜的、平和的', 'calm and peaceful; undisturbed', 'He remained placid despite the criticism.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 29'),
  ('plaintive', 'adj.', '悲哀的、哀傷的', 'sounding sad; sorrowful', 'a plaintive sigh 哀怨地嘆氣', array['melancholy 憂鬱的']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 25'),
  ('plastic', null, '可塑的、易受影響的', null, null, '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('platitude', 'n.', '平凡、陳腔濫調', 'commonplace remark or statement, esp when it is said as if it were new or interesting', 'empty platitude 空談 She began uttering liberal platitudes. 他開始說出自由派的陳腔濫調', array['triteness']::text[], '{}'::text[], 'plat(平) → 演講平鋪直敘 → 內容充滿陳腔濫調', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 29'),
  ('plausible', 'adj.', '貌似真實的、貌似有理的', 'seeming to be right or reasonable; believable', 'it seems plausible that one of two things may happen 兩件之中一件的發生是可能的 a plausible liar 貌似真實的騙子', '{}'::text[], array['implausible']::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 11'),
  ('plenitude', null, '充分、完全；大量', 'the quality or state of being full; a great sufficiency', 'She has gathered a plenitude of information on the topic. 對這topic她搜集了大量的資訊', array['abundance']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 8'),
  ('plethora', 'n.', '過量、過剩', 'quantity greater than what is needed; over-abundance', 'A plethora of books have been written on the subject.', array['plenitude', 'plentitude', 'plenty', 'superabundance']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 66 / 字根 plet: fill, full 滿、注入 / 提示 complete 完全的、完成'),
  ('pliable', 'adj.', '易彎的、柔軟的', 'easily bent, shaped or twisted; flexible', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 66 / 字根 pli, plic 彎、折、重疊 / 提示 replicate 折疊、複製'),
  ('pliant', 'adj.', '易受影響的、易彎的', 'bending easily; supple', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 66 / 字根 pli, plic 彎、折、重疊 / 提示 replicate 折疊、複製'),
  ('pliers', 'n.', '鉗子、鑷子', 'tool with long jaws which have flat surfaces that can be brought together for holding, bending, twisting or cutting wire, etc', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 66 / 字根 pli, plic 彎、折、重疊 / 提示 replicate 折疊、複製'),
  ('poignant', 'adj.', '味道濃烈的、令人傷心的、令人充滿同情的', 'affecting one''s feelings deeply, making one sad, full of pity, etc', 'a poignant perfume/ The photograph was a poignant reminder of her childhood.', array['piercing']::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 117 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('polemical', 'adj.', '引起爭論的；爭論的、辯論的', 'controversial; disputatious', 'a polemical essay || The book was criticized for its polemical tone and lack of objectivity. 這本書因其好爭的語氣和缺乏客觀性 而受到批評。', array['polemic', 'controversial']::text[], array['conciliatory(撫慰調和的)']::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 4'),
  ('politic', 'adj.', '明智的、精明的、慎重的', '(of actions) well judged; prudent', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 67 / 字根 pol 市民 / 提示 politics 政治'),
  ('pompous', 'adj.', '浮華的、愛炫耀的', 'excessively elevated or ornate; having or exhibiting self-importance : ARROGANT', 'Pompous ''International Grand Committee'' 浮誇的"國際大委員會" Signs Useless But Equally Pompous ''Declaration On Principles Of Law Governing The Internet'' 簽署無用但相同浮誇的"網路監管原則宣言"', array['arrogant', 'bombastic']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('ponder', 'v.', '仔細考慮、衡量', 'think about (sth) carefully and for a long time, esp in trying to reach a decision; consider', 'ponder her next move 思考下一步', array['chew over', 'contemplate', 'deliberate', 'entertain', 'meditate', 'ruminate', 'study', 'weigh']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('ponderous', 'adj.', '笨重的、笨拙的', 'slow and awkward because of great weight', 'For all its ponderous officialdom (官僚), the Pentagon also has an especially clear chain of command. — The Economist', array['lively(輕快活潑的)']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 43'),
  ('portend', 'v.', '預示、預先警告', 'be a sign or warning of (sth in the future); foreshadow', 'In U.S., black cats portend trouble.', '{}'::text[], '{}'::text[], 'por, pro 向前 + tend 拉、伸', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 11'),
  ('portentous', 'adj.', '預示未來的; 凶兆的﹐徵兆不祥的', 'of or like a portent; ominous', null, '{}'::text[], '{}'::text[], 'por, pro 向前 + tend 拉、伸', 1, 1, 'Mason 2000 / Mason 2000 PDF page 86 / 字根 tend, tens, tent 拉、伸 / 提示 extend 延伸'),
  ('posit', 'v.', '假定、假設；斷定、認為', 'suggest or assume (sth) as a fact; postulate', 'In his argument, he posited that humans are fundamentally selfish creatures. 在他的論述中，他假設人類從根本上是自私的生 物。', array['suggest', 'assume']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 43'),
  ('posthumous', 'adj.', '死後的、身後的', 'happening or given after death', null, '{}'::text[], '{}'::text[], 'post(後) + hum(地) + ous', 5, 2, 'Mason 2000 / Mason 2000 PDF page 40 / 字根 hum 地 / 提示 humble 卑微的、簡陋的、謙虛的'),
  ('potent', 'adj.', '強而有力的、有影響力的', '(of drugs, etc) having a strong effect', 'In the field of pharmacology 藥理學, potency is a measure of drug activity expressed in terms of the amount required to produce an effect of given intensity. A highly potent drug evokes a given response at low concentrations.', array['powerful', 'effective']::text[], array['impotent']::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 43'),
  ('pragmatic', 'adj.', '務實的', 'treating things in a sensible and realistic way; concerned with practical results', 'the pragmatic approach to problems', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
  ('preamble', 'n.', '前言、序言、先兆', 'opening statement explaining the purpose of the book, document, lecture, etc that follows', null, '{}'::text[], '{}'::text[], 'pre(前) + amble(行走)', 5, 2, 'Mason 2000 / Mason 2000 PDF page 6 / 字根 amble, ambul 行走、走來走去 / 提示 ambulance 救護車'),
  ('precarious', 'adj.', '不穩的、危險的', 'depending on chance; uncertain', 'Our financial situation is still precarious. 我們的財務狀況仍不穩定', '{}'::text[], '{}'::text[], '(1) 祈禱prec很多ous - 不停求神拜佛表危險 (2) pre前 car車 ous 多', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 8'),
  ('precede', 'v.', '在…之前、早於；開始', 'come or go before in time, order, rank, etc', 'He preceded his speech with a welcome to the guests. 他演講前先對來賓表示歡迎 // commercials preceded the movie 電影開 始前的廣告', '{}'::text[], '{}'::text[], 'pre(前) + cede(走)', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 20'),
  ('precedent', 'n.', 'n. 先例 a. 在先的、在前的', 'earlier decision, case, event, etc that is regarded as an example or rule for what comes later', 'This decision sets a precedent for future cases of a similar nature. 這一裁決為今後性質類似的案件提供了判例。', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 12'),
  ('precipitate', 'v.', '降水；加速 魯莽的', 'cause (sth) to happen suddenly or soon(er); hasten', 'Her remark precipitated my decision. 她的話促使我作出決定 // the army''s precipitate withdrawal 倉促的撤退', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 27'),
  ('preclude', 'v.', '避免、排除', 'sb from doing sth prevent (sth, or sb doing sth); make (sth) impossible', 'A rider must be visible at all times in order to preclude collisions from happening. rider總應要很醒目才能避免碰撞發生', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
  ('precocious', 'adj.', '早熟的、早成的', '(of a child) having developed certain abilities at an earlier age than usual', 'a precocious child', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 56'),
  ('precursor', 'n.', '先驅、先兆', '(of sth) person or thing that comes before sth; forerunner', 'precursors of the Romantics 浪漫主義的先驅', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 12'),
  ('predecessor', 'n.', '前任、前輩、原先的東西', 'person who held an office or position before sb else', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 15 / 字根 cede, ceed, cess 走 / 提示 proceed 前進、舉行'),
  ('predicament', 'n.', '困境、窘境', 'difficult or unpleasant situation, esp one in which sb is uncertain what to do', 'Congress to blame itself for present predicament.', '{}'::text[], '{}'::text[], 'pre(預先) + dic(命令) + ament → 預先被命令了 → 左右為難 → 困境、窘境', 1, 1, 'Mason 2000 / Mason 2000 PDF page 24 / 字根 dic, dict 說話、命令 / 提示 predict 預測'),
  ('predilection', 'n.', '偏袒、愛好', '(for sth) special liking (for sth); preference', 'Australian investors have a strong predilection for shares, particularly Australian shares.', '{}'::text[], '{}'::text[], 'pre(前) + di + lect(選擇) + ion', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 28'),
  ('predisposition', 'n.', '傾向、素質', '(to do sth) state of mind or body that makes sb liable to act in a certain way or to suffer from a certain disease', 'She has an annoying predisposition to find fault. 她有愛挑毛病這令人討厭的傾象', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('predominant', 'adj.', '佔優勢的、佔支配地位的', 'having more power or influence than others', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 25 / 字根 dom 家 / 提示 domain 領土、領域'),
  ('preeminent', null, '卓越的、顯著的', 'having paramount rank, dignity, or importance:OUTSTANDING', 'As one of the world’s preeminent smartphone companies, whatever side of the 5G line Apple ends up on will almost certainly have massive ramifications (派生影響) for the rest of the industry. — Chaim Gartenberg, The Verge', array['outstanding', 'supreme']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 40'),
  ('preempt', null, '先發制人；取代；以先買權取得', 'to replace with something considered to be of greater value or priority: to prevent from happening or taking place', 'The government preempted a coup attempt. 政府對政變先發制人 // The state law was preempted by a federal law. 取代', array['forestall', 'preclude']::text[], '{}'::text[], 'pre(預先) + empt(買) → 先買 → 以先買權取得', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 7'),
  ('preface', 'n.', '序言、緒言、引語', 'introductory statement atthe beginning of a book, esp one that explains the author''s aims', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 29 / 字根 face 臉、面 / 提示 preface 序言、緒言'),
  ('prefigure', 'v.', '預示、預想', 'represent beforehand (sth that will happen in the future); foreshadow', 'The dark clouds and strong winds prefigured the coming storm. 那些烏雲和強風預示著即將到來的暴風雨。', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 58'),
  ('prejudice', 'n.', '偏見、歧視', 'opinion, or like or dislike of sb/sth, that is not founded on experience or reason', 'We are determined to inform readers about threats, consequences and solutions based on scientific facts, not political prejudice or business interests. - theguardian.com', '{}'::text[], '{}'::text[], 'pre(前) + jud(判斷) + ice → 預先判斷 → 成見', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 25'),
  ('preliminary', null, '預備的、初步的、開始的', null, null, '{}'::text[], '{}'::text[], 'pre(前) + limin(光) + ary', 1, 1, 'Mason 2000 / Mason 2000 PDF page 47 / 字根 lumin 光 / 提示 illuminate 闡明、解釋、照亮'),
  ('premeditate', null, '預先考慮、預謀', null, 'premeditated murder 謀殺', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 40'),
  ('preponderate', 'v.', '壓倒、超過', '(fml ) be greater in influence, importance, quantity, etc (than sth else)', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 67 / 字根 ponder 重量 / 提示 ponder 仔細考慮、衡量'),
  ('prerequisite', 'adj.', '不可缺的、事先需要的', 'something that is necessary to an end or to the carrying out of a function', 'Patience and perseverance are prerequisites to success. 耐心與毅力是成功的前提', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 12'),
  ('prerogative', 'n.', '特權', 'right or privilege, esp one belonging to a particular person or group', 'As the CEO of the company, it is her prerogative to make the final decision on all major business deals. 作為公司的執行長，她有 權決定所有重要的商業交易，這是她的特權。', '{}'::text[], '{}'::text[], 'pre(預先) + rog(要求) + tive → 預先要求的權利 → 特權', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 45'),
  ('presage', 'v.', '預言', ': to give an omen or warning of : FORESHADOW; FORETELL, PREDICT', 'And nothing in her life presaged the troubles that would befall her years later.', array['augur', 'call', 'forecast', 'foretell', 'predict', 'prognosticate', 'prophesy']::text[], '{}'::text[], 'sage 智者', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('prescient', 'adj.', '有先見的、預知的', 'knowing about things before they take place; able to see into the future', 'He gained a reputation for prescience by correctly predicting the result of the election. 在正確地預測了選舉的結果後，他取得 先知的名聲', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 23'),
  ('prescription', 'n.', '命令、指示；規定、法規；處方', 'doctor''s written instruction for the composition and use of a medicine', 'I need to get a prescription from the doctor for my medication. 我需要從醫生那裡拿到我的藥方。', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 30'),
  ('pressing', 'adj.', '緊迫的、迫切的', 'urgent', 'the most pressing problems of American agriculture. — Tamar Haspel, Vox', array['acute', 'burning', 'dire', 'emergent', 'exigent', 'imperative', 'instant', 'urgent']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('presume', null, '相信、推測、自作主張、放肆', null, 'presumed innocent until proven guilty 無罪推定 // I cannot presume to know what is best for you. 我不能自作主張地為你決定什 麼是最好的。', array['suppose', 'assume']::text[], '{}'::text[], 'pre(先前) + sum(拿) + e → 事先拿 → 相信、推測、自作主張、放肆', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 47'),
  ('presumptuous', 'adj.', '專橫的、自以為是的', '(of a person or his behaviour) too bold or self-confident', 'The presumptuous doctor didn''t even bother to explain to me the treatment that I would be receiving 傲慢的醫師完全沒操煩與我 解釋我接下來要接受的治療', array['arrogant', 'haughty', 'imperious', 'pompous', 'presuming', 'pretentious', 'self-asserting', 'supercilious']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 23'),
  ('pretentious', 'adj.', '矯揉做作的；自命不凡的', 'claiming merit or importance; pompous or showy', 'Oddly, the word "pretentious" sounds pretentious. 矯揉做作聽起來很矯揉做作 That pretentious couple always serves caviar at their parties, even though they themselves dislike it. 矯揉做作的couple總在自己的派對提供魚子醬，即便他們自己都很討厭它', array['n. pretension 自負', '做作']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 15'),
  ('prevalent', 'adj.', '普遍的、盛行的', '(among/in sth/sb) existing or happening generally; widespread', 'Drone sales have been rapidly rising as the technology becomes more prevalent. — David Grossman, Popular Mechanics', array['current', 'customary', 'going', 'popular', 'prevailing', 'standard', 'stock', 'usual']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 64'),
  ('prevaricate', 'v.', '支吾其詞、說謊', 'try to avoid telling the (whole) truth by speaking in an evasive or a misleading way; equivocate', null, '{}'::text[], '{}'::text[], 'pre(預先) + vari(變化) + cate → 預先想好變化', 1, 1, 'Mason 2000 / Mason 2000 PDF page 91 / 字根 vari 變化 / 提示 variety 多樣化、變化'),
  ('prickly', null, '易怒的', 'very irritable ; having or covered with protective barbs or quills or spines or thorns etc.', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 117 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('primacy', 'n.', '卓越、第一位', 'the state of being first (as in importance, order, or rank) : PREEMINENCE', 'challenge U.S. primacy 挑戰美國首位性 Civil law took primacy over religious law. Civil law優先於religious law', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 23'),
  ('primal', null, '最初的、原始的', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 69 / 字根 prim, pri 第一、最早 / 提示 primary 主要的'),
  ('primitive', 'adj.', '原始的、遠古的；自然的', 'of or at an early stage of social development', 'primitive feelings of vengeance (報復) // A lot of the campgrounds (露營場) are primitive, and lack some common amenities (生活 便利設施) - including water. — Jamie Hale, OregonLive.com', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 44'),
  ('priority', 'n.', '在先、居前', '(state of) being more important (in rank)', null, '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('pristine', 'adj.', '原始的、清新的、純樸的', 'in its original condition; unspoilt', 'Peng-Hu has the most pristine beaches in Taiwan. 澎湖有台灣最原始的海灘', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 14'),
  ('privilege', 'n.', '特權、優特', 'special right or advantage available only to a particular person, class or rank, or to the holder of a certain position', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 69 / 字根 priv 剝奪、私人的 / 提示 deprive 剝奪、使喪失'),
  ('privy', null, '個人的、私人的', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 69 / 字根 priv 剝奪、私人的 / 提示 deprive 剝奪、使喪失'),
  ('probity', 'n.', '誠實、廉潔', 'quality of being honest and trustworthy; integrity', 'The judge''s probity was evident in the way she conducted the trial with impartiality and fairness. 該法官的誠信在她以公正和公平 的方式進行審判中表現得很明顯。 || 考題 His imperturbability(沉著) in the face of evidence indicating his deliberate fraud failed to reassured supporters of his essential probity; instead, it meant a talent for guile(狡猾) that they had never suspected.', array['honesty', 'character', 'decency', 'goodness']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 44'),
  ('proclaim', 'v.', '宣告、宣布', 'make known officially or publicly; announce', 'He proclaimed that she will run for president.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 36'),
  ('proclivity', 'n.', '傾向', '(fml ) natural inclination to do sth (esp sth bad); tendency', 'my proclivity for the rock music; a proclivity for violence', array['inclination']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 36'),
  ('procure', 'v.', '取得、獲得', 'sth (fml ) obtain sth, esp with care or effort; acquire', null, '{}'::text[], '{}'::text[], 'pre(向前) + cur(跑) + e', 1, 1, 'Mason 2000 / Mason 2000 PDF page 22 / 字根 cur, cour 跑、短 / 提示 cursor 游標'),
  ('prodigal', 'adj.', '非常浪費的、揮霍的', 'spending money or resources too freely; extravagant', 'It is short-sighted and a prodigal use of limited resources 這是短視且對於有限資源使用上的揮霍浪費', array['extravagant', 'profligate', 'spendthrift', 'squandering']::text[], array['economical', 'frugal', 'thrifty']::text[], 'pro(向前) + dig(挖) + al(=all所有) → 挖出所有的存款 → 揮霍的', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 9'),
  ('prodigy', 'n.', '神童', 'person with unusual or remarkable qualities or abilities', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 117 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('profess', null, '公開宣佈、聲稱', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 30 / 字根 fess 說 / 提示 confess 承認、公認'),
  ('profligate', 'adj.', '非常浪費的', 'recklessly extravagant or wasteful', 'The trade deficit (赤字) symbolizes a profligate America, consuming more than it produces and spending more than it has. —Philip Revzin, Wall Street Journal', array['prodigal', 'wildly extravagant']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 21'),
  ('profound', 'adj.', '深刻的、深奧的', 'deep, intense or far-reaching; verygreat', 'Her parents'' divorce had a profound effect on her life. 她父母的離異對她的生活有很深的影響 // It''s a profound book. 那是一 本深奧的書', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 21'),
  ('profuse', 'adj.', '很多的、浪費的', 'in large amounts; abundant', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 35 / 字根 fus 流 / 提示 confuse 困惑、糊塗'),
  ('progeny', 'n.', '後代、子女', 'offspring', null, '{}'::text[], '{}'::text[], 'pro(前) + gen(產生) + y → 前人生下的 → 後代、子女', 1, 1, 'Mason 2000 / Mason 2000 PDF page 36 / 字根 gen 產生、生產 / 提示 generator 發電機'),
  ('prognosis', null, '預知、（醫）預後', null, null, '{}'::text[], '{}'::text[], 'pro(前) + gnos(知道) + is → 先知道 預後(醫生根據病人病情相關因素（如疾病種類、症狀、病情分期、病理圖 像、基因、併發症、年齡等）而對未來治療結果所做的預估。)', 5, 2, 'Mason 2000 / Mason 2000 PDF page 37 / 字根 gnos, gnor 知道 / 提示 diagnose 診斷、判斷'),
  ('proliferate', 'v.', '繁殖、激增', 'produce new growth or offspring rapidly; multiply', 'The area will face an ecological disaster if the seaweed continues to proliferate at its present rate. 倘若seaweed持續以目前速度增 長，本地會遭遇生態危機', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 22'),
  ('prolific', 'adj.', '多產的、多結果的', 'producing much fruit or many flowers or offspring', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 44 / 字根 life 生命 / 提示 prolific 多產的、多結果的'),
  ('prolix', 'adj.', '囉唆的、冗長的', '(of a speech, writer, etc) using too many words and so boring to listen to or read', 'Her speech was unnecessarily prolix. 他的演說很不必要地冗長', array['verbose']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 28'),
  ('prolong', 'v.', '延長、拉長', 'make longer, esp in time; extend', null, '{}'::text[], '{}'::text[], 'pro(前) + long(長)', 2, 1, 'Mason 2000 / Mason 2000 PDF page 46 / 字根 long 長 / 提示 longevity 長命、長壽'),
  ('prominent', 'adj.', '凸出的、顯著的、卓越的', 'readily noticeable : CONSPICUOUS; widely and popularly known : LEADING; standing out or projecting beyond a surface or line', 'He quickly became prominent in the computer industry.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 28'),
  ('promote', null, '提升、促進', 'to contribute to the growth or prosperity of:FURTHER', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 53 / 字根 mot 動 / 提示 motivate 給…動機、刺激'),
  ('promulgate', 'v.', '散佈、宣揚', 'make (sth) widely known; disseminate', 'Her ideas have been widely promulgated on the Internet. 在網路上被宣揚', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 32'),
  ('pronounced', 'adj.', '明確的、明顯的', 'very noticeable', 'Flavors become more pronounced when salt is added. 加了鹽味道會更凸顯', array['conspicuous', 'flamboyant', 'marked', 'prominent', 'remarkable', 'striking']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 61'),
  ('propaganda', null, '政治宣傳', null, null, '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('propagate', 'v.', '繁殖、傳播、宣傳', 'increase the number of by a natural processfrom the parent stock', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 70 / 字根 propagare: extend 延申 / 提示 propaganda 政治宣傳'),
  ('propel', 'v.', '推進、推', 'move, driveor push (sth) forward', 'a person propelled by ambition 一個為野心所驅策的人', '{}'::text[], '{}'::text[], 'pro(前) + pel(推)', 1, 1, 'Mason 2000 / Mason 2000 PDF page 62 / 字根 pel 推、逐、驅 / 提示 compel 強迫'),
  ('propensity', 'n.', '傾向、習性', '(for doing/to do sth) (fml ) inclination or tendency', 'She''s inherited from her father a propensity to talk too much. 遺傳自他爸的多話的傾向', array['proclivity']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('prophylactic', 'adj.', '預防疾病的', 'tending to prevent a disease or misfortune', null, '{}'::text[], '{}'::text[], 'prophecy 預言 lac 說', 1, 1, 'Mason 2000 / Mason 2000 PDF page 46 / 字根 locu, log, logu, loqu 說、言 / 提示 dialogue 對話'),
  ('propitious', 'adj.', '有利的', '(fml ) giving or indicating a good chance of success; favourable', 'propitious sign', array['auspicious', 'favorable', 'heartening', 'upbeat']::text[], array['bleak', 'dark', 'depressing', 'desperate']::text[], 'propit(形近proper恰當的) + ious(多...的) → 每件事情都很恰當 → 有利的', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 62'),
  ('proprietary', 'adj.', '私有的', '(of goods) manufactured and sold by a particular firm, usu under patent', 'Microsoft, the largest commercial software company, had favored keeping its code proprietary. 一向將程式碼視為私有物（反 對開源）', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 29'),
  ('propriety', 'n.', '禮節、適當', 'state of being correct in one''s social or moral behaviour', 'When attending a wedding, there are certain proprieties that must be observed.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 44'),
  ('prosaic', 'adj.', '乏味的；平淡的；散文的', 'uninspired; unimaginative', 'For the most part, the descriptions of the books listed in the "Catalog," though informative, are relentlessly prosaic, even hackneyed. (陳腐的) — Mordecai Richler, New York Times Book Review', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 44'),
  ('proscribe', 'v.', '禁止、剝奪…的公權、放逐', 'state officially that (sth) is dangerous or forbidden', 'Louisiana proscribes the naming of public buildings for living persons. 禁止以在世的人命名公共建築', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 23'),
  ('prose', 'n.', '散文、散文體', 'written or spoken language that is not in verse form', null, '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 44'),
  ('prospect', null, '勘探、前景、前途', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 80 / 字根 spec, spic: see 看 / 提示 respect 尊敬（一再看）'),
  ('protagonist', 'n.', '主演、主角、主唱者', '(fml ) chief character in a drama; hero', 'This film has so many protagonists and the storylines are so messy.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 34'),
  ('protean', 'adj.', '變化不定的、變化多端的', 'that can change quickly and easily; variable ;', 'The actor''s protean talents allowed him to convincingly portray a wide range of characters throughout his career. 這位演員多才多 藝，使他能在演藝生涯中逼真地扮演各種角色。', '{}'::text[], '{}'::text[], 'protein 蛋白質 → 蛋白質容易變質 → 變化多端', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 68'),
  ('protract', 'v.', '延長、拖長', 'make (sth) last a long time or longer; lengthen or prolong', 'European spending negotiations are usually protracted, but this set could be especially challenging. — Tania Rabesandratana', '{}'::text[], '{}'::text[], 'pro(前) + tract(拉) → 向前拉 → 延長', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 47'),
  ('provenance', 'n.', '（常用於藝術）出處、起源', '(place of) origin', 'They try to understand the whole universe, its provenance and fate.', '{}'::text[], '{}'::text[], 'pro(向前) + ven(到來) + ance', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 64'),
  ('providential', 'adj.', '眷顧的；幸運的、及時的', 'of, relating to, or determined by Providence (天意); occurring by or as if by an intervention of Providence', 'Beatles'' success was a providential combination of talent, marketing, and timing.', array['fortuitous', 'fortunate', 'happy', 'heaven-sent', 'lucky']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 65'),
  ('provincial', 'adj.', '省的；偏狹的', 'of or concerning the regions outside the capital city of a country, especially when regarded as unsophisticated or narrow-minded.', 'The whole exhibition struck one as being very provincial. 整個展覽讓人有非常偏狹的印象 (strike = impress)', array['parochial', 'insular']::text[], '{}'::text[], '省(province)相較於市較為鄉下', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 20'),
  ('provisional', 'adj.', '臨時的、暫時性的', 'for the present time only, with the possibility of being changed', 'We have made a provisional agreement 暫時性協議 until we can finalize the details.', array['ad interim', 'impermanent', 'interim', 'provisionary', 'provisory', 'short-term', 'temporary']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 49'),
  ('provocative', 'adj.', '挑釁的、煽動的', 'tending or intended to arouse anger, annoyance, controversy, etc', 'Greek Prime Minister said that Turkey is certain to face sanctions 制裁 unless it gives up its "provocative behavior."', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 65'),
  ('proximity', 'n.', '接近、鄰近', '(to sth) nearness in space or time; closeness', 'Please don''t operate the machine in close proximity to the speaker.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 29'),
  ('pseudonym', 'n.', '假名、筆名', 'person''s name that is not his real name, esp one used by an author; pen-name', null, '{}'::text[], '{}'::text[], 'pseud(假) + onym(名稱)', 1, 1, 'Mason 2000 / Mason 2000 PDF page 57 / 字根 onym 名字 / 提示 anonymity 匿名、作者不詳'),
  ('puerile', 'adj.', '幼稚的、孩子氣的、天真的、未成熟的', 'showing immaturity; childish and silly', 'His puerile behavior during the meeting was unprofessional and inappropriate. 他在會議期間的幼稚行為是不專業和不適當 的。', '{}'::text[], array['sagacious(精明的)', 'mature(成熟的)']::text[], 'puer(=pure) + ile → 純潔的 → 幼稚的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 117 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('pugnacious', 'adj.', '愛爭吵的、愛爭鬥的、好鬥的', 'inclined or eager to fight; aggressive', 'He was a short man with heavy shoulders and a pugnacious expression. 好鬥的神情', array['truculent']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 8'),
  ('punctilious', 'adj.', '精密細心的、一絲不苟的', 'very careful to carry out one''s duties, etc correctly; very attentive to details of behaviour or ceremony', 'She''s very punctilious about grammar.', '{}'::text[], '{}'::text[], '注意到每一點', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 44'),
  ('puncture', 'n.', '刺穿、刺破', 'small hole made by a sharp point, esp one made accidentally in a tyre', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 71 / 字根 punc, pung 刺、點 / 提示 punctual 準時的、守時的'),
  ('purge', 'v.', '清洗、洗滌', 'sb sth (away) make sb clean or pure by removing (evil, sin, etc)', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 71 / 字根 pur, purg 純潔、清洗 / 提示 purify 使純潔、淨化'),
  ('purify', 'v.', '使純潔、淨化', 'sth (of sth) make sth pure by removing dirty, harmful or foreign substances', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 71 / 字根 pur, purg 純潔、清洗 / 提示 purify 使純潔、淨化'),
  ('purport', 'v.', '聲稱；據稱；意旨', 'to have the often specious appearance of being, intending, or claiming (something implied or inferred); CLAIM', 'The article seems to purport that the new drug is a cure for cancer, but there is no scientific evidence to support this claim. 這篇文章 似乎在聲稱這個新藥是能治癒癌症，但是沒有科學證據支持這個說法。', array['intend', 'look', 'mean', 'meditate', 'plan', 'propose', 'purpose']::text[], '{}'::text[], 'pur(=pro向前) + port(拿、運) → 摘要、主旨寫在文章之前 → 聲稱、意旨、主旨', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 43'),
  ('pusillanimous', 'adj.', '膽小的', 'lacking courage and resolution : marked by contemptible timidity', 'With the tough issues facing this city, the last thing we need is another pusillanimous mayor.', array['timid', 'cowardly', 'faint-hearted', 'spineless', 'craven', 'gutless']::text[], '{}'::text[], '音讀pussy(小貓) → 膽小的', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 55'),
  ('pyromania', 'n.', '縱火狂', 'illness that causes an uncontrollable desire to start fires', null, '{}'::text[], '{}'::text[], 'pyr(火) + o + mania(狂熱)', 5, 2, 'Mason 2000 / Mason 2000 PDF page 71 / 字根 pyr 火 / 提示 empyreal 天堂的'),
  ('qualify', 'v.', '使有資格、限制；限縮主張', '(sb) (for/as sth) have or give (sb) the qualities, training, etc that are necessary or suitable (for sth)', 'I''d like to qualify my criticisms of the school''s failings, by adding that it''s a very happy place.', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 4'),
  ('quandary', 'n.', '困惑、為難', 'state of not being able to decide what to do; awkward or difficult situation', 'I''ve had two job offers, and I''m in a real quandary about which one to accept. 身陷兩難', array['catch-22', 'dilemma']::text[], '{}'::text[], 'based on Latin quando "when? at what time?', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 68'),
  ('quarrel', null, '爭吵、分歧', null, null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 118 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('querulous', 'adj.', '愛發牢騷的、愛抱怨的', 'complaining; irritable', 'He became increasingly dissatisfied and querulous 愛抱怨 in his old age.', array['crabby', 'cranky', 'fussy', 'grouchy', 'grumpy']::text[], '{}'::text[], '源自 "quarrel" 爭吵 and "quarrelsome"', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('quiescent', 'adj.', '靜止的、沉默的', 'inactive; passive; quiet', 'Strikes were headed by groups of workers who had previously been quiescent.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 30'),
  ('quintessential', 'adj.', '精髓的、典型的', 'perfectly typical or representative of a particular kind of person or thing', 'This is the quintessential Los Angeles restaurant, casual but never frumpy, lively but not overheated.', '{}'::text[], '{}'::text[], 'quint(五) + ess(存在) + ence → 組成世界的五種物質 → 榜樣、精華', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 37'),
  ('quirky', null, '離奇的、古怪的', null, null, '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 63'),
  ('quixotic', 'adj.', '不切實際的、空想的', 'noble, unselfish or gallant in an extravagant or impractical way', 'Mumey had announced his candidacy in the election. It seemed a quixotic adventure, given Mumey''s lack of name recognition outside the town. 這似乎是個唐吉軻德式的空想的冒險，因為在城鎮外沒人認得他的名字', array['impractical', 'visionary', 'chimerical']::text[], '{}'::text[], '源自Don Quixote(唐吉訶德)', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 20'),
  ('quotidian', 'adj.', '日常的、平常的', 'everyday; commonplace', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 23 / 字根 di 白天、noct 夜晚 / 提示 diary 日記、日誌'),
  ('ramble', 'v.', '閒逛、漫步', 'walk for pleasure with no special destination', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 6 / 字根 amble, ambul 行走、走來走去 / 提示 ambulance 救護車'),
  ('ramification', 'n.', '後果、影響', 'part of a complex structure; secondary consequence, esp one that complicates', 'the environmental ramification from the use of coal', array['consequence']::text[], '{}'::text[], '在LOL rampage(橫衝直撞)有後果(ramification)', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 58'),
  ('rampant', 'adj.', '蔓延的；猖獗的', 'flourishing excessively; unrestrained', 'the mayor promised to put a stop to the rampant crime that plagued the city 市長承諾使如瘟疫般蔓延的猖獗犯罪停止', '{}'::text[], '{}'::text[], '近似LOL rampage 暴跳；橫衝直撞', 2, 2, 'Mason 2000 / Mason 2000 PDF page 118 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('rancor', null, '仇恨、激烈的憎惡', 'bitter deep-seated ill will', 'She answered her accusers calmly and without rancor. 她平靜且沒怨恨地回答了她的原告', '{}'::text[], '{}'::text[], '(1) rancor音讀「怨恨」 (2) 音讀「亂看」 → 招致怨恨', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 15'),
  ('rant', 'v.', '生氣叫喊；誇誇其談；責罵', '(derog ) speak loudly, violently or theatrically', '“You can rant and rave 咆哮 all you want,” she said, “but it''s not going to change things.”', '{}'::text[], '{}'::text[], '音讀「亂」 -> 叫罵', 3, 3, 'Mason 2000 / Mason 2000 PDF page 118 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('rapacious', 'adj.', '強奪的、貪婪的', 'greedy, esp for money; grasping', 'Why can''t Facebook stop its rapacious march (行進；行軍) into everybody else''s business by stealing ideas? — Eric Johnson, Recode', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 44'),
  ('rapprochement', 'n.', '（法文）（國家間）友好、和睦', 'establishment of or state of having cordial relations', 'The recent trade agreements between the two countries indicate a promising rapprochement in their relations. 最近兩國之間的貿 易協議表明他們的關系有望改善', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 68'),
  ('rarified', null, '只有一小群人知道的；稀薄的', null, 'Because of his specialized knowledge, he could only communicate with a rarified group of experts. 因為他的專業知識，他只能 與一群少數的專家溝通。', '{}'::text[], '{}'::text[], 'rar(=rare) → 很少的 → 只有一小群人知道的', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('rationale', 'n.', '根本原因、邏輯依據', 'fundamental reason for or logical basis of sth', 'The rationale for starting the school day an hour later is that kids will supposedly get an extra hour of sleep. 晚一個小時上課的邏輯 依據是小孩理論上會得到額外一小時睡眠', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 2'),
  ('ravenous', 'adj.', '狼吞虎嚥的、餓極了', 'very hungry', 'Most infants have a ravenous appetite. 胃口極好', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 65'),
  ('reactant', 'n.', '反應物', 'substance taking part in a chemical reaction', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 3 / 字根 act 行動 / 提示 activate 啟動'),
  ('reactionary', null, '保守的、反動的', 'n, adj opposing (esp political) progress or reform', 'His views were considered reactionary and out of touch with reality.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 26'),
  ('reagent', 'n.', '試劑（導致化學反應）', 'substance used to cause a chemical reaction, esp to detect another substance', 'The scientist added a reagent to the mixture to initiate the reaction.', '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 4 / 字根 ag, ig: to act 做、動 / 提示 agile 靈敏的 (AGI)'),
  ('reassure', 'v.', '使恢復信心、使確信', 'sb remove sb''s fears or doubts; make sb confident again', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 83 / 字根 sure 確定 / 提示 assure 保證、使確信'),
  ('rebellious', 'adj.', '反抗的、難控制的', 'showing a desire to rebel; not easily controlled', null, '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 55'),
  ('rebuff', 'n.', '回絕、斷然拒絕', 'unkind or contemptuous refusal or rejection (of an offer, request, friendly gesture, etc); snub', 'rebuffed the bid 斷然回絕這個出價', array['snub', 'reject sharply']::text[], '{}'::text[], 're(回) + buff(音讀「叭噗啦」) → 斷然回絕', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 26'),
  ('rebuke', 'v.', '斥責、指責', 'sb express sharp or severe disapproval to sb, esp officially; reprove sb', 'he wrote me a scathing 苛刻 rebuke 斥責.', array['admonish', 'chide', 'reprimand', 'reproach', 'reprove']::text[], array['commend', 'endorse']::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('rebut', null, '駁斥、反駁', null, 'rebutted charges 反駁指控', array['repel', 'refute']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 53'),
  ('recalcitrant', 'adj.', '頑抗的、難以控制的', 'resisting authority or discipline; disobedient', 'I am puzzled as to why the Ministry of Labor does not take more stringent action against recalcitrant employers. 我相當困惑為什麼 勞工部不對頑抗的雇主採取更加嚴格嚴厲的行動', array['unruly', 'intransigent', 'refractory']::text[], array['docile', 'tractable']::text[], '像石頭一樣堅硬的', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 35'),
  ('recant', 'v.', '改變、放棄（信仰或聲明）n. recantation', 'formally reject (a former opinion, belief, etc) as being wrong', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 13 / 字根 cant, cent, chant 唱、歌唱 / 提示 chant 歌唱、背誦'),
  ('recapitulate', 'v.', '扼要重述、概括', 'state again or summarize the main points of', 'To recapitulate what was said earlier, we need to develop new ways to gain new customers. 總結前面所說的，我們需要去開發 新的方式去贏得新客人', array['abstract', 'epitomize']::text[], '{}'::text[], '重新把重要的東西（頭）敘述', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 16'),
  ('recede', 'v.', '後退、收回；撤退撤回', '(seem to) move back from a previous position or away from an observer', 'a receding hairline 後退中的髮線', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 15 / 字根 cede, ceed, cess 走 / 提示 proceed 前進、舉行'),
  ('receptive', 'adj.', '善於接受的、從善如流地', 'able or quick to receive new ideas, suggestions, etc', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 15 / 字根 ceive, cept: take 拿、取 / 提示 receive 得到、收到'),
  ('reciprocity', 'n.', '相互性、互惠', 'principle or practice of mutual exchange, esp of making concessions or granting privileges, etc in return for concessions or privileges received', 'This would ensure that reciprocity, balance and proportion are part of the process.', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 7'),
  ('reclaim', 'v.', '重新取得', 'sth recover possession of sth', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 18 / 字根 claim, clam 喊、呼喊 / 提示 exclaim 驚叫、呼喊'),
  ('recline', 'v.', '斜倚、躺臥', 'lean or lie back in a horizontal or near-horizontal position', 'Is it OK to recline your seat? (飛機上)後仰椅子是ok的嗎?', '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 18 / 字根 clin 彎曲、傾斜 / 提示 incline 傾向'),
  ('reclusive', null, '隱遁的、隱居的', '[ recluse: ] a person who lives in seclusion', 'a reclusive neighbor', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 18 / 字根 clud, clus, claus 關閉 / 提示 close 關閉'),
  ('recognize', null, '認得、認出', null, 'I didn''t recognize you at first because of the fog.', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 36'),
  ('reconcile', null, '和解、調和', 'to make consistent or congruous', 'The teacher had to reconcile disputes among her pupils. 老師不得不調解她學生中的糾紛', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 10'),
  ('recondite', 'adj.', '深奧的（隱藏起來不外露）', '(of subjects) little known or understood; obscure', 'a recondite subject', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 7'),
  ('reconnaissance', 'n.', '偵察、勘察、事先考查', 'exploration or a survey of an area, esp for military purposes', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 118 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('rectangle', 'n.', '長方形', 'four-sided geometricfigure with four right angles, esp one with unequal adjacent sides', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 6 / 字根 angl 角 / 提示 angle 角、角度'),
  ('rectitude', 'n.', '正直、公正', 'moral correctness or straightforwardness; honesty', 'The company''s CEO was known for his rectitude and refusal to engage in unethical business practices. 這家公司的CEO以其正直 和拒絕從事不道德的商業行為而聞名。 || Many Southern Baptists (浸信會) said the series of scandals besetting (不斷侵襲的； 不時纏擾的) the convention (會議；聚會)have been particularly upsetting (苦惱的；難過的) for a religious movement that prides itself on theological (神學的) clarity and moral rectitude. — Daniel Burke, CNN', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 44'),
  ('redeem', 'v.', '贖回', 'sth (from sb/sth) buy back sth by paying the required sum; recover sth', 'His heroic act helped to redeem his past mistakes. 他的英勇行為幫助他彌補了過去的錯誤。', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 26'),
