  ('scathing', 'adj.', '刻薄的、嚴厲的', 'severe; harsh', 'a scathing review', array['acerb', 'acerbic', 'acid', 'biting', 'caustic', 'cutting', 'mordant', 'pungent']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('schematic', 'adj.', '概要的、圖解的', 'in the form of a diagram or chart', 'Schematic diagrams are often used to represent complex systems. 示意圖常被用來呈現複雜的系統。', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 54'),
  ('schism', 'n.', '分裂', 'strong disagreement, esp in a religious organization over doctrine, in which one group stops recognizing the authority of the other', 'a schism in the party 黨內分裂', array['conflict', 'discord', 'disharmony', 'dissent', 'division', 'friction', 'inharmony']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 17'),
  ('scintillate', 'v.', '（才智）煥發、發出火花', 'give off sparks; sparkle', 'Her eyes scintillated with excitement as she opened the present. 她開禮物時，眼中閃耀著興奮', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 34'),
  ('scourge', 'n.', '禍害；使苦惱，使痛苦', 'whip for flogging people', 'rat scourge 鼠害 || The pandemic has been a scourge on the world, causing immense pain and suffering. 疫情是個禍害', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 120 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('scramble', 'v.', '爬行、攀爬', 'climb or crawl quickly, usu over rough ground or with difficulty; clamber', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 6 / 字根 amble, ambul 行走、走來走去 / 提示 ambulance 救護車'),
  ('scruple', 'n.', '謹慎小心、顧忌猶豫', 'feeling that prevents one from doing or allowing sth that one thinks may be wrong', 'She had no scruples; she would do whatever she wanted to. 她是一個毫無顧忌的人；她想要做什麼就做什麼', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 26'),
  ('scrupulous', 'adj.', '謹慎小心的、一絲不苟的、正直的', 'extremely careful and thorough; paying great attention to details', 'I have been absolutely scrupulous in observing all the rules.', array['painstaking']::text[], '{}'::text[], '海關人員將箱子撕開來檢查 → 一絲不苟的、正直的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 120 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('scrutinize', null, '詳細檢查、細讀', 'examine closely and critically', 'I closely scrutinized my opponent''s every move.', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 5'),
  ('secede', 'v.', '正式脫離或退出', '(fml ) withdraw (from membership of an organization, state, etc)', null, '{}'::text[], '{}'::text[], 'se(分開) + cede(走)', 5, 2, 'Mason 2000 / Mason 2000 PDF page 15 / 字根 cede, ceed, cess 走 / 提示 proceed 前進、舉行'),
  ('seclude', 'v.', '使隔離、使孤立、使隱退、使隱居', 'sb/oneself (fml ) keep sb/oneself apart (from others)', null, '{}'::text[], '{}'::text[], 'se: separate', 1, 1, 'Mason 2000 / Mason 2000 PDF page 18 / 字根 clud, clus, claus 關閉 / 提示 close 關閉'),
