  ('secular', 'adj.', '世俗的', 'not concerned with spiritual or religious affairs; worldly', null, '{}'::text[], array['clerical(神職人員的)']::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 120 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('sedative', 'n.', '鎮靜劑、使安靜的、使鎮靜的', 'drug or medicine that sedates', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 77 / 字根 sed 坐 / 提示 sediment 沉積、沉澱'),
