  ('shrewd', 'adj.', '善於判斷的、精明的、敏銳的', 'having or showing good judgement and common sense; astute', 'Her brother is a shrewd businessman. 她兄弟是個精明的生意人。', '{}'::text[], '{}'::text[], '數', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('shrug', 'v.', '聳肩', 'raise (one''s shoulders) slightly to express doubt, indifference, ignorance', 'shrug their shoulders 聳肩', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 63'),
  ('shun', 'v.', '避開、躲開', 'keep away from (sth/sb); avoid', 'She was shunned by her former friends after she went astray. 她偏離正道後，從前的朋友都迴避她', array['avoid', 'dodge', 'duck']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 12'),
  ('sift', 'v.', '篩、過濾', 'put (sth) through a sieve', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 120 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('simultaneous', 'adj.', '同時發生的、同時存在的', 'happening or done at the same time (as sth)', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 78 / 字根 simil, simul 像、相同 / 提示 similar 相似的'),
