  ('skulduggery', 'n.', '欺騙、詐欺', 'deception and planning of evil acts; trickery', 'political skulduggery 政治欺詐', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 120 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('slake', 'v.', '平息、使滿足', 'satisfy', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 120 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('slander', null, '誹謗、詆毀', null, null, array['defame']::text[], '{}'::text[], '上升成功的路上總會遭人誹謗 → 誹謗', 5, 2, 'Mason 2000 / Mason 2000 PDF page 75 / 字根 scan, scend, scent: climb 攀、爬 / 提示 ascend 上升、攀登、上坡'),
