  ('slumber', 'v.', '睡、睡眠', 'sleep, esp peacefully and comfortably', 'He awoke from a deep slumber.', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 68'),
  ('slur', null, '誹謗、中傷', 'an insulting or disparaging remark or innuendo : ASPERSION', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 121 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('snobbery', null, '勢利', 'conduct by someone who pays too much respect to social position and wealth, or who despises people of a lower social position', 'Michel is a snob. 勢利眼', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('solicit', 'v.', '懇求、請求、招攬', '(for sth); (sth) (from sb) (fml ) ask (sb) for (eg money, help, votes) earnestly; try to obtain (sth)', 'solicit donations 募款 Emerson was later found guilty of soliciting prostitution. 性交易', array['appeal (to)', 'beg', 'implore', 'petition', 'plead (to)', 'pray', 'supplicate']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 7'),
  ('soliloquy', 'n.', '自言自語、戲劇獨白', 'speaking one''s thoughts aloud, esp in a play when a character does this without another character being present on stage', null, '{}'::text[], '{}'::text[], 'sol(孤單、獨自) + i(SE) + loqu(說) + y', 1, 1, 'Mason 2000 / Mason 2000 PDF page 46 / 字根 locu, log, logu, loqu 說、言 / 提示 dialogue 對話'),
  ('solitary', 'adj.', '單獨的、獨自的', '(living) alone; without companions', 'Most cats are solitary creatures. 獨居動物', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 63'),
  ('solitude', 'n.', '孤獨、寂寞、隱居', 'being alone without companions; solitary state', null, '{}'::text[], '{}'::text[], null, 5, 2, 'Mason 2000 / Mason 2000 PDF page 79 / 字根 sol 孤單、安慰 / 提示 isolate 孤立、隔離'),
  ('solo', 'n.', '單獨的、單獨表演的', 'piece of music, dance, entertainment, etc performed by only one person', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 79 / 字根 sol 孤單、安慰 / 提示 isolate 孤立、隔離'),
  ('somatic', null, '身體的、軀體的', 'pertaining to the body; physical', 'somatic cell 人類基因改造可以簡單分為身體細胞（Somatic Cell） 改造和生殖細胞 （Germline Cell） 改造兩大類， 兩者背後的倫理道德考量大相逕庭。編輯身體細胞不會遺傳，被編輯過的基因只會存在於病人的特定細胞之內，並不 會遺傳到下一代身上', '{}'::text[], '{}'::text[], 'somatic音讀"someone" → 某人的 → 身體的、軀體的', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 54'),
  ('somnolent', 'adj.', '想睡的、催眠的', 'almost asleep; sleepy; drowsy', 'The sound of the rain outside was so somnolent that I couldn''t keep my eyes open. 雨聲如此催眠，以至於我無法睜開眼睛。', array['lethargic']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 30'),
  ('sonorous', 'adj.', '響亮的、洪亮的', 'having a full deep sound', 'a deep, sonorous voice', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 46'),
  ('sophistication', 'n.', '老於世故、有教養', 'quality of being sophisticated', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 80 / 字根 soph 智慧 / 提示 sophomore 大二'),
  ('sophistry', 'n.', '詭辯、謬論', 'use of sophisms', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 80 / 字根 soph 智慧 / 提示 sophomore 大二'),
  ('soporific', null, '令人想睡的', 'n, adj causing sleep', 'The boring lecture was so soporific that many of the students dozed off in their seats. 那場無聊的演講太催眠了，許多學生在座 位上打瞌睡。', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 30'),
  ('sordid', 'adj.', '骯髒的、汙穢的', 'marked by baseness or grossness : VILE; (of conditions, places, etc) dirty and unpleasant; squalid', 'sordid apartments', array['dirty', 'dusty', 'filthy', 'foul', 'grimy', 'muddy', 'nasty', 'stained', 'sullied']::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 54'),
  ('sound', null, '健全的、完好的；合理的', 'SOUND emphasizes the absence of disease, weakness, or malfunction', 'a sound mind 健全的心靈 a sound estimate 合理的估計', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('sovereign', 'adj.', '最高統治者、元首', '(of power) without limit; highest', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 72 / 字根 reg, reign 統治 / 提示 regulate 管制、調整'),
