  ('specious', 'adj.', '似是而非的、華而不實的', 'seeming right or true but actually wrong or false', 'specious argument, specious theories', array['misleading', 'deceptive', 'false', 'fallacious', 'spurious']::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 2'),
  ('speculate', 'v.', '推測；沈思、思索；投機', 'form opinions without having definite or complete knowledge or evidence; guess', 'She could only speculate about her parent''s motives. 他只能推測他家長的動機', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 23'),
  ('speculative', 'adj.', '投機的、思索的、推測的', 'concerned with or formed by speculation', 'Due to the speculative nature of the evidences, the judge could not arrive at a concrete decision. 因為所有的證據都是推測性的， 法官無法作出具體的結論。', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 30'),
  ('spontaneous', 'adj.', '自發的、自主的、自然的', 'done,happening, said, etc because of a voluntary impulse from within, not caused or suggested by sth/sb outside', 'the audience broke into spontaneous applause', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 54'),
  ('sporadic', 'adj.', '零星的', 'happening or seen only occasionally or in a few places; occurring irregularly', 'sporadic success(偶爾的成功)', array['occasional', 'infrequent', 'irregular']::text[], array['incessant', 'constant']::text[], 'spor(=sper發散) → 發散的 → 零星的', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
  ('spurious', 'adj.', '假的、站不住腳的、欺騙性的', 'not genuine or authentic; false or fake', 'spurious sympathy 假同情', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 12'),
  ('spurn', 'v.', '摒棄、藐視', 'reject or refuse scornfully or contemptuously', 'He (Galileo) is lionized for advocating a heliocentric view (行星繞著太陽轉) of our solar system, spurning Church doctrine (教條) and becoming a heretic (異教徒、持異端邪說者).', '{}'::text[], '{}'::text[], 'spur(馬刺) → 應該要拋棄', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('squander', 'v.', '揮霍、浪費', 'sth waste (time, money, etc); use sth wastefully', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 121 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('staggering', 'adj.', '驚人的', 'astonishing; shocking', 'It costs a staggering $50,000 per week to keep the museum open to the public.', array['marvelous', 'miraculous', 'stunning', 'sublime']::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 68'),
