  ('staunch', null, '堅定的、忠誠的', null, 'John Bolton staunchly stood by the president.', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 82 / 字根 sta, st 站 / 提示 obstacle 障礙、干擾'),
  ('sterling', null, '優秀的、出色的、高尚的', null, 'sterling character', '{}'::text[], '{}'::text[], 'ster(=star星的) → 如星星一般璀璨', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 54'),
  ('stifle', 'v.', '使窒息、悶死', 'feel or make unable to breathe (easily) because of lack of fresh air; suffocate', 'Musk accused Twitter of stifling free speech.', array['choke', 'smother', 'strangle', 'suffocate']::text[], '{}'::text[], null, 3, 3, 'Mason 2000 / Mason 2000 PDF page 121 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('stigma', 'n.', '污名、恥辱感', 'mark of shame or disgrace; shameful feeling or reputation', 'We can end the stigma that has forced too many to suffer in silence. - Theresa May tweeted on World Mentel Health Day', '{}'::text[], '{}'::text[], '字源：古希臘時代，原意是熱鐵烙下的標記。這些標記通常被打在奴隸、罪犯或叛徒—有污點的人、不潔者—身 上。今天這個詞的引申義被廣泛使用，即恥辱和詆毀的標誌。', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 24'),
  ('stigmatize', null, '侮辱、指責、污名化', 'describe smb scornfully', 'Labeling a person with a mental illness can stigmatize and isolate them. 將一個人標籤為患有心理疾病可能會令他們感到被 污名化和孤立。', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 82 / 字根 sti, stimul 刺、點、刺激 / 提示 stimulus 刺激、刺激物'),
  ('stilted', 'adj.', '呆板的、生硬的、不自然的', '(of a manner of talking, writing, behaving, etc) stiff and unnatural; artificial', 'We made stilted conversation.', '{}'::text[], '{}'::text[], 'stilted音讀「死呆子」 → 呆板的、生硬的、不自然的', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 46'),
  ('stint', 'v.', '吝嗇、節省', 'on sth; sb/oneself (usu in negative sentences ) restrict, limit sb/oneself to a small amount of (esp food)', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 83 / 字根 sti, stimul 刺、點、刺激 / 提示 stimulus 刺激、刺激物'),
  ('stipulate', 'v.', '規定；約定', 'state (sth) clearly and firmly as a requirement', 'The cease-fire was stipulated by the treaty. 停火在條約中被規範 The rules stipulate that players must wear uniforms. 規則要求 玩家必須穿著制服', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 2000 / Mason 2000 PDF page 121 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('stoicism', 'n.', '斯多葛哲學、禁慾主義', 'behaving stoically; indifference to pleasure or pain : IMPASSIVENESS', null, '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 68'),
  ('stratification', null, '分層、階層', null, 'In an economy of unprecedented wealth inequality, the affordability crisis further exacerbates social and racial stratification. — New York Times', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 54'),
  ('strip', 'v.', '剝去、剝光', 'sth (from/off sth/sb); sth/sb (of sth); sth (off) take off (clothes, coverings, parts, etc) from sb/sth', 'The court stripped the man of his parental rights after he was found guilty of child abuse. 這名男子因被判有虐待兒童罪名而被 法庭剝奪了他的侵權', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 46'),
  ('stymie', 'v.', '阻礙、妨礙', 'to present an obstacle to : stand in the way of', 'The aging U.S. population could stymie future job growth. 老化的美國人口可能阻礙未來就業成長', array['clog', 'encumber', 'fetter', 'hamper', 'handicap', 'hinder', 'impede', 'inhibit', 'manacle', 'obstruct', 'shackle']::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 20'),
  ('subdue', 'v.', '征服、壓制、減輕', 'bring under control by force; defeat', 'subdued his fears 壓抑他的恐懼', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 27'),
  ('subjugate', 'v.', '征服、鎮壓', 'gain controlof (a country, etc); subdue; conquer', 'The emperor sought to subjugate the neighboring territories and expand his empire. 皇帝試圖征服鄰近的領土，擴張帝國。', '{}'::text[], '{}'::text[], 'sub(下面) + jug(結合) + ate → 使加入其下 → 征服', 3, 3, 'Mason 2000 / Mason 2000 PDF page 42 / 字根 jug 結合 / 提示 subjugate 征服、鎮壓'),
  ('submission', 'n.', '屈從、歸順、投降', 'acceptance of another`s power; submitting', null, '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 51 / 字根 miss, mis, mit 投、送、發 / 提示 missile 飛彈、導彈'),
  ('subordinate', 'adj.', '(a.)次要的、下級的 (v.) 使服從、使列入下級', '(to sb) lower in rank or position', 'Literature is becoming subordinated to criticism, a reversal of priorities. 文學反倒次級於文學批評了', '{}'::text[], '{}'::text[], 'sub(下面) + ordin(順序) + ate', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 42'),
  ('subscribe', 'v.', '捐助、訂購', '(to sth) (agree to) contribute (a sum of money)', null, '{}'::text[], '{}'::text[], 'sub(下面) + scrib(寫) + e → 簽名同意', 1, 1, 'Mason 2000 / Mason 2000 PDF page 76 / 字根 scribe, script 寫、紀錄 / 提示 describe 描述、形容'),
  ('subservient', 'adj.', '奉承的、卑屈的、充當下手的', '(often derog ) giving too much respect, obedience, etc; submissive', null, '{}'::text[], '{}'::text[], 'sub(下面) + serv(服務) + ient → 在下面服務 → 次要的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 78 / 字根 serv保存、服務 / 提示 preserve 保存'),
  ('subside', 'v.', '下陷；退去；平息', 'sink to a lower or to the normal level', 'The flood waters subsided. 洪水退去了 His anger subsided. 他的怒氣平息了', '{}'::text[], '{}'::text[], 'sub(下面) + sid(坐) + e → 坐下去 → 下陷', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 11'),
  ('substantial', 'adj.', '大量的、實在的', 'large in amount; considerable', 'a substantial wage 高額薪資 // a substantial number of people 大量的人們', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 33'),
  ('substantiate', 'v.', '證實', 'give facts to support (a claim, statement, etc); prove', 'they had found nothing to substantiate the allegations 他們找不到任何東西可證實指控', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 9'),
  ('subtract', 'v.', '減去、減掉', 'sth take (a number or quantity) away from (another number, etc)', null, '{}'::text[], '{}'::text[], null, 2, 1, 'Mason 2000 / Mason 2000 PDF page 88 / 字根 tract 拖、拉 / 提示 distract 分心、轉移'),
  ('subvert', 'v.', '顛覆、推翻', 'destroy the authority of', 'subvert the U.S. election (黑客行為試圖) 顛覆選舉', '{}'::text[], '{}'::text[], 'sub(下面) + vert(轉)', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 31'),
  ('successively', null, '接連地、連續地', null, 'Because of his good public image he has successively gained office. 由於他在公眾中的良好形象，他已連續競選獲勝。', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 15 / 字根 cede, ceed, cess 走 / 提示 proceed 前進、舉行'),
  ('succinct', 'adj.', '簡明的、簡潔的', 'expressed briefly and clearly; concise', 'Buyers demand clear, succinct and unequivocal (清楚的；不含糊的) analysis and predictions (from research firms). 客戶要求研 究公司提供清楚、簡明與不含糊地分析與預測', array['aphoristic', 'capsule', 'compact', 'concise', 'laconic', 'pithy', 'terse']::text[], '{}'::text[], 'suc(下面) + cinct(束起) → 衣服束起做事 → 簡潔', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 56'),
  ('succumb', 'v.', '屈從、因…死亡', '(fml ) stop resisting (temptation, illness, attack, etc); yield', 'succumb to temptation 屈從於誘惑', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 27'),
  ('suffice', 'v.', '足夠、（食物）滿足', '(not in the continuous tenses ) (fml ) be enough (for sb/sth); be adequate', 'I think, Mr. Fox, a simple phone call might have sufficed. - Lau, The Dark Knight', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 31 / 字根 fec, fic, fict: to do 做 / 提示 deficient 有缺陷的、不足的'),
  ('suffrage', 'n.', '選舉權﹐投票權', 'right to vote in political elections', 'champion women''s suffrage 捍衛支持女性投票權', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 38'),
  ('sumptuous', 'adj.', '豪華的、奢華的、奢侈的', 'looking expensive and splendid', 'a sumptuous banquet 盛宴', '{}'::text[], '{}'::text[], null, 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 68'),
  ('supercilious', 'adj.', '目中無人的、高傲的', 'thinking or showing that one thinks one is better than other people; arrogant and disdainful', 'reacted to their breach (違反) of etiquette (禮儀) with a supercilious smile', array['arrogant', 'haughty', 'imperious', 'presumptuous', 'pretentious']::text[], '{}'::text[], 'super(超) + cil(眉)', 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 27'),
  ('superfluous', 'adj.', '多餘的、累贅的', 'more than is needed or wanted', 'He had already been told, so our comments were superfluous. 他已被告知，所以我們的評論是多餘的', '{}'::text[], '{}'::text[], 'super(超過) + flu(流) + ous → 多得流出來 → 多餘的', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
  ('superlative', 'adj.', '最高的、最好的', 'of the highest degree or quality', null, '{}'::text[], '{}'::text[], 'super(上面) + lat(提拿) + ive', 1, 1, 'Mason 2000 / Mason 2000 PDF page 43 / 字根 lat: carry 提拿、運送 / 提示 superlative 最高的、最好的'),
  ('supersede', 'v.', '淘汰、取代', 'take the place of be introduced so as to be used instead of (sth/sb)', 'Studies that are wrong will be superseded by better studies with different results. Studies that are right will be corroborated by other good studies.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 30'),
  ('supplant', 'v.', '排擠、取代', 'take the place of (sb/sth); replace', 'With inflation slated to 即將 exceed 1.3 million percent this year, gold has supplanted the worthless national currency. 黃金取代了毫 無價值的本國貨幣', '{}'::text[], '{}'::text[], 'sup(下面) + plant(栽種、播種)', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 43'),
  ('supplement', 'n.', '補充、增加', 'thing added to sth else to improve or complete it', 'she should take vitamin supplements 她應該服用維他命補充劑', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 12'),
  ('supplicate', 'v.', '懇求、乞求', 'sth (fml ) ask (sb) humbly or pleadingly for sth', 'with bowed heads they supplicated their Lord', '{}'::text[], '{}'::text[], 'sup(下面) + plic(折疊) + ate', 5, 2, 'Mason 2000 / Mason 2000 PDF page 67 / 字根 pli, plic 彎、折、重疊 / 提示 replicate 折疊、複製'),
  ('suppress', 'v.', '鎮壓、抑制', 'put an end to (sth), esp by force; crush', 'suppress a riot 鎮壓暴動', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 6'),
  ('surfeit', 'n.', '過量、過度', '(of sth) too much of sth, esp of food and drink', 'After eating an enormous dinner, I had a surfeit of food and couldn''t eat another bite.', '{}'::text[], '{}'::text[], 'sur(超) + feit(做) → 超量、過度', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 58'),
  ('surmise', 'v.', '推測、猜測、臆測', 'suppose (sth) without having evidence that makes it certain; guess', 'The police surmise that the robbers have fled the country. 據警方推測，搶劫犯已經逃離這個國家', array['assume', 'conjecture', 'guess', 'imagine', 'presume', 'speculate', 'suppose', 'suspect']::text[], '{}'::text[], 'sur(超越) + mis(丟) + e → 投石問路 → 猜測、臆測', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 60'),
  ('surmount', 'v.', '克服、戰勝', 'deal with (a difficulty, etc); overcome', 'With determination and perseverance, she was able to surmount the challenges of starting her own business. 透過決心和毅力，她 成功地克服了創業過程中的各種挑戰。', array['beat', 'best', 'conquer', 'defeat', 'dispatch', 'master', 'upend']::text[], '{}'::text[], 'sur(超越) + mount(山)', 2, 2, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 60'),
  ('surpass', 'v.', '勝過、優於、大於、多於', 'sb/sth (in sth) (fml ) do or be better than sb/sth; exceed sb/sth', null, '{}'::text[], '{}'::text[], 'sur(超越) + pass(通過)', 2, 1, 'Mason 2000 / Mason 2000 PDF page 60 / 字根 pass 通過 / 提示 surpass 勝過、優於'),
  ('surreptitious', 'adj.', '秘密的、偷偷摸摸的、鬼鬼祟祟的', 'done or acting secretly or stealthily', 'She made a surreptitious attempt to read her sister''s diary while she was out of the room. 她趁妹妹不在房間的時候偷偷摸摸地 試圖看她的日記。', array['clandestine', 'covert', 'furtive', 'secret', 'sneaky', 'stealth', 'stealthy', 'undercover']::text[], '{}'::text[], 'rept 爬 reptile 爬蟲類', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 45'),
  ('surrogate', 'n.', '代替品、代理人', '(fml ) person or thing that acts or is used instead of another; substitute', 'For centuries, animals have been used as surrogates for people in experiments to assess the effects of therapeutic and other agents that might later be used in humans.', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 30'),
