  ('syntax', 'n.', '語法、句法', '(rules for the) arrangement of words into phrases and phrases into sentences', 'the grammar or syntax of the language', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 54'),
  ('synthesize', null, '綜合、合成', null, 'He synthesized old and new ideas to form his theory.', '{}'::text[], '{}'::text[], 'syn(共同) + thes(放) + ize → 放到一起', 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 5'),
  ('taciturn', 'adj.', '沉默的', 'saying very little; uncommunicative', 'It was okay for boxers of 50 years ago to be taciturn, but today the champion is expected to be an entertainer. 50年前拳擊手沈默寡 言是可以的。但現在冠軍被期待作為一個藝人', array['laconic', 'reticent']::text[], array['loquacious(多話的)', 'prolix(囉唆的)', 'voluble(多話的)']::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 3'),
