  ('tantalize', null, '引逗、使著迷', 'to tease or torment by or as if by presenting something desirable to the view but continually keeping it out of reach', 'a tantilizing piece of gossip', '{}'::text[], '{}'::text[], null, 1, 1, 'Mason 2000 / Mason 2000 PDF page 122 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('tantamount', 'adj.', '同等的、相當於', 'to sth equal in effect to sth; as good as sth', 'Ireland''s blasphemy (褻瀆神明) ban was enshrined (銘記) in the constitution in 1937, during an era when church and state were seen as a single entity and defaming (誹謗) the established religion was tantamount to treason (叛國). - https://www.jurist.org', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 41'),
  ('taxing', null, '負擔沈重的', 'onerous, wearing', null, array['onerous', 'wearing']::text[], '{}'::text[], '稅負(tax)十分沈重 → taxing負擔沈重的', 1, 1, 'Mason 2000 / Mason 2000 PDF page 122 / 字根 vulg 普通 / 提示 vulgar 粗俗的、下流的'),
  ('tedious', 'adj.', '冗長乏味的、使人厭煩的', 'tiresome because of being too long, slow or dull; boring', 'a tedious ceremony', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 26'),
  ('temerity', 'n.', '魯莽、冒失、不自量力', 'audacity; rashness', 'She had the temerity to call me a liar. 他竟冒失地稱我為騙子', array['audacity', 'brass', 'brazenness', 'cheek', 'crust', 'effrontery', 'presumption', 'presumptuousness', 'sauce']::text[], '{}'::text[], '音讀「他媽的」 → 在不正確的場合罵髒話 → 魯莽的', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 54'),
  ('temperate', 'adj.', '（溫帶氣候的；氣候）溫和的、（飲食）適度的', 'behaving with temperance(1); showing self-control', 'Charles was temperate in his consumption of both food and drink 他在飲食上都相當節制 Chile has one of the largest temperate forests in the southern hemisphere 智利有南半球上最大的溫帶雨林', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 8'),
  ('temporal', 'adj.', '時間的、世俗的', 'of worldly affairs, ie not spiritual; secular', 'The Church has no temporal power in the modern state. 教會在現代國家中沒有世俗的權力', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 24'),
  ('tenable', 'adj.', '站得住腳的、經得起批判的', 'that can be defended successfully against opposition or attack', '"The argument that the earth is flat is not tenable in light of scientific evidence. 在科學證據面前，地球是平的的論點是不能維 持的。', '{}'::text[], '{}'::text[], null, 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 47'),
  ('tenacious', 'adj.', '堅持的、頑強的、固執的', 'sticking or clinging firmly together or to an object', 'The company has a tenacious hold on the market. // Japan''s frustrating four-year war against Chiang Kai-shek''s feckless but tenacious Chinese army. —David M. Kennedy', '{}'::text[], '{}'::text[], null, 4, 4, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 31'),
  ('tendentious', 'adj.', '有偏見的、傾向性的', '(of a speech, a piece of writing, etc) aimed at helping a cause; not impartial', 'He made some extremely tendentious remarks. 他做一些極端有傾向性的評論', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 8'),
