  ('transcendent', null, '超驗的；超越的、卓越的', 'extending or lying beyond the limits of ordinary experience; surpassing the ordinary; exceptional.', 'a firm belief in angels, demons, and other transcendent beings 相信天使、惡魔和其他超驗的事物 the star player''s transcendent performance helped the team to a surprise victory 傑出的表現幫助團隊取得意外的勝利', '{}'::text[], '{}'::text[], null, 5, 5, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 8'),
  ('transcribe', 'v.', '抄寫、謄寫', 'sth copy sth in writing', 'I need to transcribe the interview I recorded earlier today. 我需要把我今天早些時候錄下來的採訪打成文字稿。', '{}'::text[], '{}'::text[], 'trans(轉換) + scrib(寫) + e', 3, 3, 'Mason 1000; Mason 2000 / primary: Mason 1000 PDF page 45'),
